package com.voicescape;

import lombok.Getter;
import lombok.Setter;
import lombok.extern.slf4j.Slf4j;

import java.io.*;
import java.net.*;
import java.nio.charset.StandardCharsets;
import java.util.List;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.ScheduledFuture;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.function.Consumer;

@Slf4j
public class NetworkClient
{

	private static final byte MSG_HELLO = 0x01;
	private static final byte MSG_HASH_LIST_UPDATE = 0x02;
	private static final byte MSG_AUDIO_FRAME = 0x03;
	private static final byte MSG_IDENTITY = 0x04;


	private static final byte MSG_HELLO_ACK = 0x10;
	private static final byte MSG_KEY_ROTATION = 0x11;
	private static final byte MSG_AUDIO_FRAME_FROM_SERVER = 0x12;
	private static final byte MSG_SERVER_ERROR = 0x13;

	private static final int PROTOCOL_VERSION = 1; // Change for later versions only for sever compatibillity
	private static final int MAX_TCP_FRAME_SIZE = 1500;
	private static final int MAX_AUDIO_PAYLOAD = 1400;
	private static final byte MSG_UDP_REGISTER = 0x20;
	private static final int UDP_BUFFER_SIZE = 2048; // Increased to fit raw PCM frames plus headers
	private static final long UDP_REGISTER_INTERVAL_MS = 30_000;
	private static final long HEARTBEAT_INTERVAL_MS = 10_000;
	private static final long RECONNECT_DELAY_MS = 5_000;
	private static final long HANDSHAKE_TIMEOUT_MS = 10_000;

	private final VoiceChatConfig config;
	private final AudioPlaybackManager playbackManager;
	@Getter
	private final AtomicBoolean running = new AtomicBoolean(false);
	private final AtomicInteger audioSequenceNumber = new AtomicInteger(0);

	private volatile Socket socket;
	private volatile DataOutputStream out;
	private volatile DataInputStream in;

	private volatile String sessionId="";
	@Getter
	private volatile byte[] currentDailyKey;
	private volatile byte[] udpKey;
	private volatile String playerName;
	private volatile long lastHashListTime = 0;
	private volatile long lastUdpRegisterTime = 0;

	private volatile DatagramSocket udpSocket;
	private volatile InetAddress serverAddr;
	private volatile int serverPort;

	private ScheduledExecutorService scheduler;
	private ScheduledFuture<?> connectionTask;
	private ScheduledFuture<?> heartbeatTask;
	private Future<?> udpReceiveTask;

	@Setter
    private volatile Consumer<String> statusListener;

	public NetworkClient(VoiceChatConfig config, AudioPlaybackManager playbackManager)
	{
		this.config = config;
		this.playbackManager = playbackManager;
	}

    private void reportStatus(String message)
	{
		Consumer<String> l = statusListener;
		if (l != null)
		{
			l.accept(message);
		}
	}


	public boolean isConnected()
	{
		Socket s = socket;
		return s != null && s.isConnected() && !s.isClosed();
	}

	public void connect(String playerName)
	{
		disconnect();
		this.playerName = playerName;
		running.set(true);

		scheduler = Executors.newScheduledThreadPool(3, r ->
		{
			Thread thread = new Thread(r, "VoiceScape-Network");
			thread.setDaemon(true);
			return thread;
		});
		scheduleConnection(0);
	}

	public void disconnect()
	{
		running.set(false);
		reportStatus("Disconnected");
		closeSocket();
		cancelScheduledTasks();
		if (scheduler != null)
		{
			scheduler.shutdownNow();
			scheduler = null;
		}
	}

	private synchronized void scheduleConnection(long delayMs)
	{
		if (!running.get() || scheduler == null || scheduler.isShutdown())
		{
			return;
		}

		connectionTask = scheduler.schedule(this::connectionLoop, delayMs, TimeUnit.MILLISECONDS);
	}

	private void cancelScheduledTasks()
	{
		if (connectionTask != null)
		{
			connectionTask.cancel(false);
			connectionTask = null;
		}
		if (heartbeatTask != null)
		{
			heartbeatTask.cancel(false);
			heartbeatTask = null;
		}
		if (udpReceiveTask != null)
		{
			udpReceiveTask.cancel(false);
			udpReceiveTask = null;
		}
	}

	private String computeIdentityHash()
	{
		byte[] key = currentDailyKey;
		String name = playerName;
		if (key == null || name == null || name.isEmpty())
		{
			return "";
		}
		return HashUtil.hmac(key, name);
	}

	public synchronized void sendHashListUpdate(List<String> nearbyHashes)
	{
		if (!isConnected() || out == null)
		{
			return;
		}

		try
		{
			int limit = Math.min(nearbyHashes.size(), 50);
			ByteArrayOutputStream entries = new ByteArrayOutputStream();
			DataOutputStream entryWriter = new DataOutputStream(entries);
			int count = 0;
			for (int i = 0; i < limit; i++)
			{
				byte[] hashBytes = nearbyHashes.get(i).getBytes(StandardCharsets.UTF_8);
				if (hashBytes.length > 255)
				{
					continue;
				}
				entryWriter.writeShort(hashBytes.length);
				entryWriter.write(hashBytes);
				count++;
			}

			ByteArrayOutputStream byteArrayOutputStream = new ByteArrayOutputStream();
			DataOutputStream msg = new DataOutputStream(byteArrayOutputStream);
			msg.writeByte(MSG_HASH_LIST_UPDATE);
			msg.writeShort(count);
			msg.write(entries.toByteArray());
			writeFramed(out, byteArrayOutputStream.toByteArray());
			lastHashListTime = System.currentTimeMillis();
		}
		catch (IOException e)
		{
			log.error("Failed to send hash list update", e);
			closeSocket();
		}
	}

	public void sendAudioFrame(int sequenceNumber, byte[] payload)
	{
		if (!isConnected())
		{
			return;
		}

		if (payload.length > MAX_AUDIO_PAYLOAD)
		{
			log.debug("Audio payload too large ({} bytes), dropping", payload.length);
			return;
		}

		DatagramSocket ds = udpSocket;
		InetAddress addr = serverAddr;
		byte[] key = udpKey;
		if (ds == null || ds.isClosed() || addr == null || key == null)
		{
			return;
		}

		try
		{
			byte[] encrypted = UdpCrypto.encrypt(key, sequenceNumber, payload);
			ByteArrayOutputStream baos = new ByteArrayOutputStream();
			DataOutputStream msg = new DataOutputStream(baos);
			msg.writeByte(MSG_AUDIO_FRAME);
			msg.writeInt(sequenceNumber);
			msg.write(encrypted);
			byte[] data = baos.toByteArray();
			ds.send(new DatagramPacket(data, data.length, addr, serverPort));
		}
		catch (IOException e)
		{
			log.debug("UDP audio send failed: {}", e.getMessage());
		}
	}

	public int nextSequenceNumber()
	{
		return audioSequenceNumber.getAndIncrement();
	}

	private Socket createSocket(String host, int port) throws Exception
	{
		return new Socket(host, port);
	}

	public void performServerHandshake() throws IOException {
		sendHello();
		readHelloAck();
		sendIdentity(computeIdentityHash());
	}

	private void connectionLoop()
	{
		if (!running.get())
		{
			return;
		}

		try
		{
			String address = config.serverAddress();
			String[] parts = address.split(":");
			String host = parts[0];
			int port = parts.length > 1 ? Integer.parseInt(parts[1]) : 5555;

			log.info("Connecting to voice server at {}:{}", host, port);
			reportStatus("Connecting to " + host + ":" + port + "...");

			socket = createSocket(host, port);
			socket.setTcpNoDelay(true);
			socket.setKeepAlive(true);
			socket.setSoTimeout((int) HANDSHAKE_TIMEOUT_MS);

			out = new DataOutputStream(socket.getOutputStream());
			in = new DataInputStream(socket.getInputStream());
			performServerHandshake();

			socket.setSoTimeout(0);
			log.info("Connected to voice server, session: {}", sessionId);
			reportStatus("Connected");
			openUdpChannel(host, port);
			startHeartbeat();

			while (running.get() && isConnected())
			{
				readMessage();
			}
		}
		catch (java.net.ConnectException e)
		{
			if (running.get())
			{
				log.warn("Connection refused: {}", e.getMessage());
				reportStatus("Connection refused");
			}
		}
		catch (java.net.UnknownHostException e)
		{
			if (running.get())
			{
				log.warn("Unknown host: {}", e.getMessage());
				reportStatus("Unknown host");
			}
		}
		catch (java.net.SocketTimeoutException e)
		{
			if (running.get())
			{
				log.warn("Connection timed out: {}", e.getMessage());
				reportStatus("No response from server");
			}
		}
		catch (Exception e)
		{
			if (running.get())
			{
				log.warn("Connection failed: {}", e.getMessage());
			}
		}
		finally
		{
			closeSocket();
		}

		if (running.get())
		{
			log.debug("Reconnecting in {}ms", RECONNECT_DELAY_MS);
			scheduleConnection(RECONNECT_DELAY_MS);
		}
	}

	private void writeFramed(DataOutputStream dst, byte[] payload) throws IOException
	{
		if(payload.length>MAX_TCP_FRAME_SIZE) {
			throw new IOException("Sending frame too large: " + payload.length);
		}
		dst.writeShort(payload.length);
		dst.write(payload);
		dst.flush();
	}

	private DataInputStream readFrame() throws IOException
	{
		DataInputStream input = in;
		if (input == null)
		{
			throw new IOException("Connection closed");
		}
		int length = input.readUnsignedShort();
		if (length > MAX_TCP_FRAME_SIZE)
		{
			throw new IOException("Incoming frame too large: " + length);
		}
		byte[] buf = new byte[length];
		input.readFully(buf);
		return new DataInputStream(new java.io.ByteArrayInputStream(buf));
	}

	private synchronized void sendHello() throws IOException
	{
		byte[] sessionIdBytes = sessionId.getBytes(StandardCharsets.UTF_8);
		ByteArrayOutputStream byteArrayOutputStream = new ByteArrayOutputStream();
		DataOutputStream msg = new DataOutputStream(byteArrayOutputStream);
		msg.writeByte(MSG_HELLO);
		msg.writeInt(PROTOCOL_VERSION);
		msg.writeShort(sessionIdBytes.length);
		msg.write(sessionIdBytes);
		writeFramed(out, byteArrayOutputStream.toByteArray());
	}

	private synchronized void sendIdentity(String identityHash) throws IOException
	{
		byte[] hashBytes = identityHash.getBytes(StandardCharsets.UTF_8);
		ByteArrayOutputStream byteArrayOutputStream = new ByteArrayOutputStream();
		DataOutputStream msg = new DataOutputStream(byteArrayOutputStream);
		msg.writeByte(MSG_IDENTITY);
		msg.writeShort(hashBytes.length);
		msg.write(hashBytes);
		writeFramed(out, byteArrayOutputStream.toByteArray());
	}

	private void readHelloAck() throws IOException
	{
		DataInputStream msg = readFrame();

		int type = msg.readByte() & 0xFF;

		if(type == (MSG_SERVER_ERROR & 0xFF)) {
				int errLen = msg.readUnsignedShort();
				if (errLen > 512)
				{
					throw new IOException("Server error message too long: " + errLen);
				}
				byte[] errBytes = new byte[errLen];
				msg.readFully(errBytes);
				String errorMsg = new String(errBytes, StandardCharsets.UTF_8);
				reportStatus(errorMsg);
				throw new IOException("Server rejected connection: " + errorMsg);
		} else if(type != (MSG_HELLO_ACK & 0xFF)) {
			throw new IOException("Expected HelloAck, got: 0x" + Integer.toHexString(type));
		}

		int sessionIdLen = msg.readUnsignedShort();
		if (sessionIdLen > 256)
		{
			throw new IOException("SessionId too long: " + sessionIdLen);
		}
		byte[] sessionIdBytes = new byte[sessionIdLen];
		msg.readFully(sessionIdBytes);
		sessionId = new String(sessionIdBytes, StandardCharsets.UTF_8);

		int keyLen = msg.readUnsignedShort();
		if (keyLen > 64)
		{
			throw new IOException("Key too long: " + keyLen);
		}
		byte[] key = new byte[keyLen];
		msg.readFully(key);
		currentDailyKey = key;

		int udpKeyLen = msg.readUnsignedShort();
		if (udpKeyLen > 64)
		{
			throw new IOException("UDP key too long: " + udpKeyLen);
		}
		byte[] uk = new byte[udpKeyLen];
		msg.readFully(uk);
		udpKey = uk;
	}

	private void readMessage() throws IOException
	{
		DataInputStream msg = readFrame();

		int type = msg.readByte() & 0xFF;

		switch (type)
		{
			case (MSG_KEY_ROTATION & 0xFF):
				int keyLen = msg.readUnsignedShort();
				if (keyLen > 64)
				{
					throw new IOException("Rotated key too long: " + keyLen);
				}
				byte[] newKey = new byte[keyLen];
				msg.readFully(newKey);
				currentDailyKey = newKey;
				log.debug("Key rotated");


				sendIdentity(computeIdentityHash());
				break;

			case (MSG_SERVER_ERROR & 0xFF):
				int errLen = msg.readUnsignedShort();
				if (errLen > 512)
				{
					throw new IOException("Server error message too long: " + errLen);
				}
				byte[] errBytes = new byte[errLen];
				msg.readFully(errBytes);
				String errorMsg = new String(errBytes, StandardCharsets.UTF_8);
				reportStatus(errorMsg);
				break;

			default:
				log.debug("Unknown message type: 0x{}", Integer.toHexString(type));
				break;
		}
	}

	private void startHeartbeat()
	{
		if (heartbeatTask != null)
		{
			heartbeatTask.cancel(false);
		}
		if (scheduler == null || scheduler.isShutdown())
		{
			return;
		}
		heartbeatTask = scheduler.scheduleWithFixedDelay(
			this::sendHeartbeat,
			HEARTBEAT_INTERVAL_MS,
			HEARTBEAT_INTERVAL_MS,
			TimeUnit.MILLISECONDS);
	}

	private void sendHeartbeat()
	{
		if (!running.get() || !isConnected())
		{
			return;
		}

		try
		{
			long timeSinceLastHash = System.currentTimeMillis() - lastHashListTime;
			if (timeSinceLastHash >= HEARTBEAT_INTERVAL_MS)
			{
				synchronized (this)
				{
					if (out != null)
					{
						ByteArrayOutputStream baos = new ByteArrayOutputStream();
						DataOutputStream msg = new DataOutputStream(baos);
						msg.writeByte(MSG_HASH_LIST_UPDATE);
						msg.writeShort(0);
						writeFramed(out, baos.toByteArray());
					}
				}
			}

			if (System.currentTimeMillis() - lastUdpRegisterTime >= UDP_REGISTER_INTERVAL_MS)
			{
				sendUdpRegistration();
			}
		}
		catch (IOException e)
		{
			log.debug("Heartbeat failed: {}", e.getMessage());
			closeSocket();
		}
	}

	private synchronized void closeSocket()
	{
		closeUdpSocket();
		try
		{
			if (socket != null)
				socket.close();
		}
		catch (IOException e)
		{
			log.debug("Error closing socket", e);
		}
		socket = null;
		out = null;
		in = null;
		playbackManager.flushLine();

	}

	private void openUdpChannel(String host, int port)
	{
		try
		{
			serverAddr = InetAddress.getByName(host);
			serverPort = port;
			udpSocket = new DatagramSocket();
			sendUdpRegistration();
			startUdpReceiveTask();
			log.debug("UDP audio channel opened to {}:{}", host, port);
		}
		catch (Exception e)
		{
			log.debug("UDP audio unavailable, using TCP fallback: {}", e.getMessage());
			closeUdpSocket();
		}
	}

	private void sendUdpRegistration()
	{
		if (udpSocket == null || udpSocket.isClosed() || sessionId == null || serverAddr == null)
		{
			return;
		}
		try
		{
			byte[] sidBytes = sessionId.getBytes(StandardCharsets.UTF_8);
			ByteArrayOutputStream baos = new ByteArrayOutputStream();
			DataOutputStream msg = new DataOutputStream(baos);
			msg.writeByte(MSG_UDP_REGISTER);
			msg.writeShort(sidBytes.length);
			msg.write(sidBytes);
			byte[] data = baos.toByteArray();
			udpSocket.send(new DatagramPacket(data, data.length, serverAddr, serverPort));
			lastUdpRegisterTime = System.currentTimeMillis();
		}
		catch (IOException e)
		{
			log.debug("UDP registration failed: {}", e.getMessage());
		}
	}

	private void startUdpReceiveTask()
	{
		if (udpReceiveTask != null)
		{
			udpReceiveTask.cancel(false);
		}
		if (scheduler == null || scheduler.isShutdown())
		{
			return;
		}

		udpReceiveTask = scheduler.submit(() ->
		{
			byte[] buf = new byte[UDP_BUFFER_SIZE];
			if (udpSocket == null)
			{
				return;
			}
			while (running.get() && !udpSocket.isClosed())
			{
				try
				{
					DatagramPacket packet = new DatagramPacket(buf, buf.length);
					udpSocket.receive(packet);
					log.debug("Received UDP Packet");
					handleUdpPacket(buf, packet.getLength());
				}
				catch (SocketException e)
				{
					break;
				}
				catch (Exception e)
				{
					if (running.get())
					{
						log.debug("UDP receive error: {}", e.getMessage());
					}
				}
			}
		});
	}

	/**
	 * Parse an inbound UDP packet from the server.
	 * Expected format: [0x12][sender_hash_len:u16][sender_hash][seq:u32][opus_payload...]
	 */
	private void handleUdpPacket(byte[] data, int length)
	{
		if (length < 1)
		{
			return;
		}
		try
		{
			DataInputStream msg = new DataInputStream(
				new java.io.ByteArrayInputStream(data, 0, length));

			int type = msg.readByte() & 0xFF;
			if (type != (MSG_AUDIO_FRAME_FROM_SERVER & 0xFF))
			{
				return;
			}

			int hashLen = msg.readUnsignedShort();
			if (hashLen > 256)
			{
				return;
			}
			byte[] senderHash = new byte[hashLen];
			msg.readFully(senderHash);
			int seq = msg.readInt();

			int payloadLen = length - 1 - 2 - hashLen - 4;
			if (payloadLen <= 0 || payloadLen > MAX_AUDIO_PAYLOAD)
			{
				return;
			}
			byte[] encrypted = new byte[payloadLen];
			msg.readFully(encrypted);

			byte[] key = udpKey;
			if (key == null)
			{
				return;
			}
			byte[] payload = UdpCrypto.decrypt(key, seq, encrypted);

			playbackManager.receiveAudio(
				new String(senderHash, StandardCharsets.UTF_8), seq, payload);
		}
		catch (Exception e)
		{
			log.debug("Malformed UDP packet: {}", e.getMessage());
		}
	}

	private void closeUdpSocket()
	{
		DatagramSocket ds = udpSocket;
		if (ds != null)
		{
			ds.close();
		}
		udpSocket = null;
		serverAddr = null;
	}
}

package com.voicescape;

import java.awt.Color;
import java.awt.Dimension;
import java.awt.Graphics2D;
import java.util.Set;
import javax.inject.Inject;
import net.runelite.api.Client;
import net.runelite.api.Player;
import net.runelite.api.Point;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayLayer;
import net.runelite.client.ui.overlay.OverlayPosition;

public class VoiceOverlay extends Overlay
{
	private static final Color SPEAKER_COLOR = new Color(0, 200, 83, 200);
	private static final Color SPEAKER_BG = new Color(0, 0, 0, 128);
	private static final int ICON_SIZE = 18;
	private static final int ICON_OFFSET_Y = -8;

	private final Client client;
	private final VoiceChatConfig config;
	private final VoiceChatPlugin plugin;

	@Inject
	public VoiceOverlay(Client client, VoiceChatConfig config, VoiceChatPlugin plugin)
	{
		this.client = client;
		this.config = config;
		this.plugin = plugin;
		setPosition(OverlayPosition.DYNAMIC);
		setLayer(OverlayLayer.ABOVE_SCENE);
		setPriority(Overlay.PRIORITY_MED);
	}

	@Override
	public Dimension render(Graphics2D graphics)
	{
		if (!config.showOverlay())
		{
			return null;
		}

		if (plugin.isLocalPlayerTransmitting() && (plugin.getNetworkClient().isConnected() || config.localLoopback()))
		{
			Player local = client.getLocalPlayer();
			if (local != null)
			{
				Point textLocation = local.getCanvasTextLocation(graphics, "", local.getLogicalHeight() + 60);
				if (textLocation != null)
				{
					renderSpeakerIcon(graphics, textLocation);
				}
			}
		}


		Set<String> activeSpeakerHashes = plugin.getActiveSpeakerHashes();
		if (activeSpeakerHashes == null || activeSpeakerHashes.isEmpty())
		{
			return null;
		}

		byte[] dailyKey = plugin.getCurrentDailyKey();
		if (dailyKey == null)
		{
			return null;
		}

		for (Player player : client.getTopLevelWorldView().players())
		{
			if (player == null || player.getName() == null || player == client.getLocalPlayer())
			{
				continue;
			}

			String playerHash = HashUtil.hmac(dailyKey, player.getName());
			if (!activeSpeakerHashes.contains(playerHash))
			{
				continue;
			}

			Point textLocation = player.getCanvasTextLocation(graphics, "", player.getLogicalHeight() + 60);
			if (textLocation == null)
			{
				continue;
			}

			renderSpeakerIcon(graphics, textLocation);
		}

		return null;
	}

	private void renderSpeakerIcon(Graphics2D graphics, Point location)
	{
		int x = location.getX() - ICON_SIZE / 2;
		int y = location.getY() + ICON_OFFSET_Y - ICON_SIZE;

		int pad = 3;
		// Background rounded rectangle — sized to contain the full icon
		graphics.setColor(SPEAKER_BG);
		graphics.fillRoundRect(x - pad, y - pad, ICON_SIZE + pad * 2, ICON_SIZE + pad * 2, 8, 8);

		graphics.setColor(SPEAKER_COLOR);

		// Center the speaker vertically within the icon area
		// Speaker body (small rectangle on the left)
		int bodyW = 4;
		int bodyH = 6;
		int bx = x + 2;
		int by = y + (ICON_SIZE - bodyH) / 2;
		graphics.fillRect(bx, by, bodyW, bodyH);

		// Speaker cone (trapezoid flaring right from the body)
		int coneW = 5;
		int flare = 3; // how much wider the cone is than the body
		int[] triX = {bx + bodyW, bx + bodyW, bx + bodyW + coneW, bx + bodyW + coneW};
		int[] triY = {by, by + bodyH, by + bodyH + flare, by - flare};
		graphics.fillPolygon(triX, triY, 4);

		// Sound waves (arcs) — centered on the cone mouth
		int arcX = bx + bodyW + coneW;
		int arcCenterY = by + bodyH / 2;
		int arcH1 = bodyH + flare * 2 + 2;
		int arcH2 = bodyH + flare * 2 + 6;
		graphics.drawArc(arcX, arcCenterY - arcH1 / 2, 4, arcH1, -50, 100);
		graphics.drawArc(arcX + 3, arcCenterY - arcH2 / 2, 4, arcH2, -50, 100);
	}
}

package com.voicescape;

import javax.crypto.Cipher;
import javax.crypto.spec.IvParameterSpec;
import javax.crypto.spec.SecretKeySpec;

public final class UdpCrypto
{
	private UdpCrypto() {}

	public static byte[] encrypt(byte[] key, int sequenceNumber, byte[] data)
	{
		return process(key, sequenceNumber, data, Cipher.ENCRYPT_MODE);
	}

	public static byte[] decrypt(byte[] key, int sequenceNumber, byte[] data)
	{
		return process(key, sequenceNumber, data, Cipher.DECRYPT_MODE);
	}

	private static byte[] process(byte[] key, int sequenceNumber, byte[] data, int mode)
	{
		try
		{
			SecretKeySpec keySpec = new SecretKeySpec(key, 0, 16, "AES");

			byte[] iv = new byte[16];
			iv[0] = (byte) (sequenceNumber >> 24);
			iv[1] = (byte) (sequenceNumber >> 16);
			iv[2] = (byte) (sequenceNumber >> 8);
			iv[3] = (byte) sequenceNumber;

			Cipher cipher = Cipher.getInstance("AES/CTR/NoPadding");
			cipher.init(mode, keySpec, new IvParameterSpec(iv));
			return cipher.doFinal(data);
		}
		catch (Exception e)
		{
			throw new RuntimeException("UDP crypto failed", e);
		}
	}
}

package com.voicescape;

import lombok.Getter;
import lombok.extern.slf4j.Slf4j;

import javax.sound.sampled.AudioSystem;
import javax.sound.sampled.DataLine;
import javax.sound.sampled.Mixer;
import javax.sound.sampled.SourceDataLine;
import java.util.Collections;
import java.util.Map;
import java.util.Set;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.ScheduledFuture;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicBoolean;

@Slf4j
public class AudioPlaybackManager {
	private static final int MAX_SPEAKERS = 10;
	private static final int FRAME_SIZE_SAMPLES = AudioDeviceManager.FRAME_SIZE_BYTES / 2;

	private final VoiceChatConfig config;
	private final AtomicBoolean running = new AtomicBoolean(false);
	private ScheduledExecutorService scheduler;
	private ScheduledFuture<?> playbackTask;
	private final Map<String, SpeakerState> speakers = new ConcurrentHashMap<>();
	@Getter
	private final Set<String> activeSpeakers = ConcurrentHashMap.newKeySet();
	@Getter
	private final Set<String> mutedHashes = ConcurrentHashMap.newKeySet();
	@Getter
	private final Set<String> unmutedDefaultHashes = ConcurrentHashMap.newKeySet();
	private volatile Map<String, Integer> nearbyDistances = Collections.emptyMap();
	private SourceDataLine line;

	private final short[] decodedBuffer = new short[AudioDeviceManager.FRAME_SIZE_BYTES / 2];
	private final short[] loopbackShortBuffer = new short[AudioDeviceManager.FRAME_SIZE_BYTES / 2];
	private final byte[] outputByteBuffer = new byte[AudioDeviceManager.FRAME_SIZE_BYTES];

	public AudioPlaybackManager(VoiceChatConfig config) {
		this.config = config;
	}

	public synchronized void start() {
		if (running.get()) {
			return;
		}

		running.set(true);
		scheduler = Executors.newSingleThreadScheduledExecutor(r -> {
			Thread thread = new Thread(r, "VoiceScape-Playback");
			thread.setDaemon(true);
			return thread;
		});
		scheduler.execute(() -> {
			openLine();
			if (line == null) {
				log.debug("No playback line available, playback scheduler exiting");
				running.set(false);
				scheduler.shutdown();
				return;
			}

			playbackTask = scheduler.scheduleWithFixedDelay(
				this::playbackTick,
				0,
				10,
				TimeUnit.MILLISECONDS);
		});
	}

	public void flushLine() {
		SourceDataLine l = line;
		if (l != null) {
			l.flush();
		}
	}

	public void clearMutedPlayers() {
		mutedHashes.clear();
	}

	public void mutePlayer(String hash) {
		mutedHashes.add(hash);
	}

	public void unmutePlayer(String hash) {
		mutedHashes.remove(hash);
	}

	public boolean isPlayerMuted(String hash) {
		return mutedHashes.contains(hash);
	}

	public void updateNearbyDistances(Map<String, Integer> distances) {
		this.nearbyDistances = distances;
	}

	public void receiveLoopback(byte[] pcm) {
		if (config.deafened() || line == null) {
			return;
		}

		double volume = (config.outputVolume() / 100.0);

		AudioDeviceManager.bytesToShorts(pcm, pcm.length, loopbackShortBuffer);

		for (int i = 0; i < loopbackShortBuffer.length; i++) {
			loopbackShortBuffer[i] = (short) Math.max(-32768, Math.min(32767, loopbackShortBuffer[i] * volume));
		}

		AudioDeviceManager.shortsToBytes(loopbackShortBuffer, outputByteBuffer);
		line.write(outputByteBuffer, 0, outputByteBuffer.length);
	}

	public void receiveAudio(String senderIdentityHash, int sequenceNumber, byte[] payload) {
		if (config.deafened() || mutedHashes.contains(senderIdentityHash)) {
			return;
		}

		if (!speakers.containsKey(senderIdentityHash) && speakers.size() >= MAX_SPEAKERS) {
			return;
		}

		SpeakerState state = speakers.computeIfAbsent(senderIdentityHash, k -> new SpeakerState());

		state.jitterBuffer.put(sequenceNumber, payload);
		state.lastReceiveTime = System.currentTimeMillis();
	}

	public void openLine() {
		try {
			DataLine.Info info = new DataLine.Info(SourceDataLine.class, AudioDeviceManager.FORMAT);

			String deviceName = config.outputDevice();
			if (deviceName != null && !deviceName.isEmpty()) {
				Mixer.Info mixerInfo = AudioDeviceManager.findMixer(deviceName, false);
				if (mixerInfo != null) {
					Mixer mixer = AudioSystem.getMixer(mixerInfo);
					line = (SourceDataLine) mixer.getLine(info);
				} else {
					log.debug("Output device '{}' not found, falling back to default", deviceName);
					line = (SourceDataLine) AudioSystem.getLine(info);
				}
			} else {
				line = (SourceDataLine) AudioSystem.getLine(info);
			}

			int bufferBytes = AudioDeviceManager.FRAME_SIZE_BYTES * 8;
			line.open(AudioDeviceManager.FORMAT, bufferBytes);
			line.start();
			log.debug("Audio playback line opened (buffer {} bytes)", bufferBytes);
		} catch (Exception e) {
			log.debug("Failed to open audio playback line", e);
			line = null;
		}
	}

	private void playbackTick() {
		if (!running.get()) {
			return;
		}

		try {
			float[] mixBuffer = new float[FRAME_SIZE_SAMPLES];
			int senderCount = 0;

			long now = System.currentTimeMillis();
			for (Map.Entry<String, SpeakerState> entry : speakers.entrySet()) {
				SpeakerState state = entry.getValue();

				if (now - state.lastReceiveTime > 1500) {
					activeSpeakers.remove(entry.getKey());
					continue;
				}

				Integer distance = nearbyDistances.get(entry.getKey());
				if (distance == null) {
					activeSpeakers.remove(entry.getKey());
					continue;
				}

				float distScale = 1.0f - (float) (Math.log(distance + 1) / Math.log(16));
				distScale = Math.max(0f, distScale);
				if (distScale <= 0f) {
					activeSpeakers.remove(entry.getKey());
					continue;
				}

				if (!state.jitterBuffer.isReady() || !state.jitterBuffer.canPoll()) {
					continue;
				}

				byte[] payload = state.jitterBuffer.poll();

				try {
					if (payload == null)
						continue;

					AudioCodec.decode(payload, 0, payload.length, decodedBuffer);

					for (int i = 0; i < decodedBuffer.length; i++) {
						if (i < mixBuffer.length) {
							mixBuffer[i] += decodedBuffer[i] * distScale;
						}
					}
					senderCount++;
					activeSpeakers.add(entry.getKey());
				} catch (Exception e) {
					log.debug("Audio processing error for sender {}: {}", entry.getKey(), e.getMessage());
				}
			}

			if (senderCount > 0) {
				double volume = config.outputVolume() / 100.0;

				float maxVal = 0;
				for (float v : mixBuffer) {
					maxVal = Math.max(maxVal, Math.abs(v));
				}

				float masterScale = 1.0f;
				if (maxVal > 32767) {
					masterScale = 32767f / maxVal;
				}

				for (int i = 0; i < mixBuffer.length; i++) {
					loopbackShortBuffer[i] = (short) Math.max(-32768, Math.min(32767, mixBuffer[i] * masterScale * volume));
				}

				AudioDeviceManager.shortsToBytes(loopbackShortBuffer, outputByteBuffer);
				line.write(outputByteBuffer, 0, outputByteBuffer.length);
			}

			// Cleanup speaker
			speakers.entrySet().removeIf(e -> {
				if (now - e.getValue().lastReceiveTime > 8000) {
					activeSpeakers.remove(e.getKey());
					e.getValue().jitterBuffer.reset();
					return true;
				}
				return false;
			});
		} catch (Exception e) {
			log.debug("Error in audio playback tick", e);
		}
	}

	public void shutdown() {
		running.set(false);
		if (playbackTask != null) {
			playbackTask.cancel(true);
			playbackTask = null;
		}
		closeLine();
		if (scheduler != null) {
			scheduler.shutdownNow();
			scheduler = null;
		}
	}

	public void closeLine() {
		if (line != null) {
			try {
				line.stop();
				line.close();
			} catch (Exception e) {
				log.debug("Error closing playback line", e);
			}
			line = null;
		}
	}

	private static class SpeakerState {
		final JitterBuffer jitterBuffer = new JitterBuffer();
		volatile long lastReceiveTime = System.currentTimeMillis();
	}
}

package com.voicescape;

public class AudioCodec {

    public static int encode(short[] pcm, byte[] out) {
        int outIdx = 0;
        short lastSample = 0;

        for (short sample : pcm) {
            int delta = sample - lastSample;
            lastSample = sample;

            int n = (delta << 1) ^ (delta >> 31);

            while ((n & ~0x7F) != 0) {
                out[outIdx++] = (byte) ((n & 0x7F) | 0x80);
                n >>>= 7;
            }
            out[outIdx++] = (byte) n;
        }
        return outIdx;
    }


    public static void decode(byte[] in, int inOffset, int inLength, short[] pcm) {
        int inIdx = inOffset;
        int endIdx = inOffset + inLength;
        short lastSample = 0;
        int pcmIdx = 0;

        while (inIdx < endIdx && pcmIdx < pcm.length) {
            int n = 0;
            int shift = 0;
            byte b;
            do {
                if (inIdx >= endIdx) break;
                b = in[inIdx++];
                n |= (b & 0x7F) << shift;
                shift += 7;
            } while ((b & 0x80) != 0);

            int delta = (n >>> 1) ^ -(n & 1);
            short sample = (short) (lastSample + delta);
            pcm[pcmIdx++] = sample;
            lastSample = sample;
        }
    }
}

package com.voicescape;

import lombok.extern.slf4j.Slf4j;

@Slf4j
public class JitterBuffer
{
	private static final int BUFFER_SIZE = 64;
	private static final int MASK = BUFFER_SIZE - 1;

	private static final int PREBUFFER_FRAMES = 10;

	private final byte[][] slots = new byte[BUFFER_SIZE][];
	private final boolean[] occupied = new boolean[BUFFER_SIZE];
	private int nextReadSeq = -1;
	private int maxReceivedSeq = -1;
	private boolean primed = false;

    public synchronized void put(int sequenceNumber, byte[] opusPayload)
	{
		if (nextReadSeq == -1)
		{
			nextReadSeq = sequenceNumber;
		}

		if (sequenceNumber < nextReadSeq)
		{
			return;
		}

		if (sequenceNumber >= nextReadSeq + BUFFER_SIZE)
		{
			for (int i = 0; i < BUFFER_SIZE; i++)
			{
				slots[i] = null;
				occupied[i] = false;
			}
			nextReadSeq = sequenceNumber;
			maxReceivedSeq = -1;
			primed = false;
        }

		int idx = sequenceNumber & MASK;
		slots[idx] = opusPayload;
		occupied[idx] = true;

		if (sequenceNumber > maxReceivedSeq)
		{
			maxReceivedSeq = sequenceNumber;
		}
	}

	public synchronized boolean isReady()
	{
		if (primed)
		{
			return true;
		}
		if (bufferedCount() >= PREBUFFER_FRAMES)
		{
			primed = true;
			return true;
		}
		return false;
	}

	public synchronized boolean canPoll()
	{
		if (nextReadSeq == -1)
		{
			return false;
		}
		int idx = nextReadSeq & MASK;
		if (occupied[idx])
		{
			return true;
		}
		return nextReadSeq < maxReceivedSeq;
	}

	public synchronized byte[] poll()
	{
		if (nextReadSeq == -1)
		{
			return null;
		}

		int idx = nextReadSeq & MASK;
		if (occupied[idx])
		{
			byte[] data = slots[idx];
			slots[idx] = null;
			occupied[idx] = false;
			nextReadSeq++;
			return data;
		}

		if (nextReadSeq < maxReceivedSeq)
		{
			nextReadSeq++;
			return null;
		}
		return null;
	}

	public synchronized void reset()
	{
		for (int i = 0; i < BUFFER_SIZE; i++)
		{
			slots[i] = null;
			occupied[i] = false;
		}
		nextReadSeq = -1;
		maxReceivedSeq = -1;
		primed = false;
	}

	public synchronized int bufferedCount()
	{
		int count = 0;
		for (boolean b : occupied)
		{
			if (b) count++;
		}
		return count;
	}
}

