    static JPanel build(QuestRow row)
    {
        final String text;
        final Color bg;

        final QuestReadiness r = row.getReadiness();
        switch (r)
        {
            case DONE:
                text = "Done";
                bg = new Color(54, 94, 64);
                break;
            case IN_PROGRESS:
                text = "In progress";
                bg = new Color(88, 86, 58);
                break;
            case BLOCKED:
                text = "Blocked";
                bg = new Color(92, 64, 64);
                break;
            case READY:
            default:
