package com.ironpath.util;

/**
 * OSRS experience table helpers.
 *
 * RuneLite's API does not expose exact per-skill XP for an Ironman plan simulation,
 * so we convert from a conservative baseline: the minimum XP for the current real level.
 *
 * This still improves correctness over heuristics when applying quest XP rewards.
 */
public final class XpTable
{
    private static final int MAX_LEVEL = 126;
    private static final int[] XP_FOR_LEVEL = build();

    private XpTable() {}

    public static int xpForLevel(int level)
    {
        int l = clamp(level, 1, MAX_LEVEL);
        return XP_FOR_LEVEL[l];
    }

    public static int levelForXp(int xp)
    {
        int x = Math.max(0, xp);
        int lo = 1;
        int hi = MAX_LEVEL;

        while (lo < hi)
        {
            int mid = (lo + hi + 1) >>> 1;
            if (XP_FOR_LEVEL[mid] <= x)
            {
                lo = mid;
            }
            else
            {
                hi = mid - 1;
            }
        }

        return lo;
    }

    private static int[] build()
    {
        // Standard RuneScape formula. Index 0 unused; XP_FOR_LEVEL[level] = minimum XP for that level.
        int[] xp = new int[MAX_LEVEL + 1];
        int points = 0;

        xp[1] = 0;
        for (int lvl = 2; lvl <= MAX_LEVEL; lvl++)
        {
            points += (int) Math.floor(lvl - 1 + 300.0 * Math.pow(2.0, (lvl - 1) / 7.0));
            xp[lvl] = points / 4;
        }
        return xp;
    }

    private static int clamp(int v, int lo, int hi)
    {
        if (v < lo) return lo;
        if (v > hi) return hi;
        return v;
    }
}

package com.ent.discord;

import com.ent.EntConfig;
import com.google.common.base.Strings;
import java.awt.image.BufferedImage;
import java.io.ByteArrayOutputStream;
import java.io.IOException;
import javax.imageio.ImageIO;
import javax.inject.Inject;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.Client;
import net.runelite.client.ui.DrawManager;
import static net.runelite.http.api.RuneLiteAPI.GSON;
import okhttp3.Call;
import okhttp3.Callback;
import okhttp3.HttpUrl;
import okhttp3.MediaType;
import okhttp3.MultipartBody;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.RequestBody;
import okhttp3.Response;

@Slf4j
public class DiscordWebhook
{
	private final Client client;
	private final EntConfig config;
	private OkHttpClient okHttpClient;
	private DrawManager drawManager;

	@Inject
	DiscordWebhook(Client client, EntConfig config, OkHttpClient okHttpClient, DrawManager drawManager) {
		this.client = client;
		this.config = config;
		this.okHttpClient = okHttpClient;
		this.drawManager = drawManager;
	}

	public void sendWebhook(DiscordWebhookBody discordWebhookBody, boolean sendScreenshot)
	{
		String configUrl = config.discordWebhookUrl();
		if (Strings.isNullOrEmpty(configUrl)) { return; }

		HttpUrl url = HttpUrl.parse(configUrl);
		MultipartBody.Builder requestBodyBuilder = new MultipartBody.Builder()
			.setType(MultipartBody.FORM)
			.addFormDataPart("payload_json", GSON.toJson(discordWebhookBody));

		if (sendScreenshot)
		{
			sendWebhookWithScreenshot(url, requestBodyBuilder);
		}
		else
		{
			buildRequestAndSend(url, requestBodyBuilder);
		}
	}

	void sendWebhookWithScreenshot(HttpUrl url, MultipartBody.Builder requestBodyBuilder)
	{
		drawManager.requestNextFrameListener(image ->
		{
			BufferedImage bufferedImage = (BufferedImage) image;
			byte[] imageBytes;
			try
			{
				imageBytes = convertImageToByteArray(bufferedImage);
			}
			catch (IOException e)
			{
				log.warn("Error converting image to byte array", e);
				return;
			}

			requestBodyBuilder.addFormDataPart("file", "image.png",
				RequestBody.create(MediaType.parse("image/png"), imageBytes));
			buildRequestAndSend(url, requestBodyBuilder);
		});
	}

	private void buildRequestAndSend(HttpUrl url, MultipartBody.Builder requestBodyBuilder)
	{
		RequestBody requestBody = requestBodyBuilder.build();
		Request request = new Request.Builder()
			.url(url)
			.post(requestBody)
			.build();
		sendRequest(request);
	}

	private void sendRequest(Request request)
	{
		okHttpClient.newCall(request).enqueue(new Callback()
		{
			@Override
			public void onFailure(Call call, IOException e)
			{
				log.debug("Error submitting webhook", e);
			}

			@Override
			public void onResponse(Call call, Response response) throws IOException
			{
				response.close();
			}
		});
	}

	private static byte[] convertImageToByteArray(BufferedImage bufferedImage) throws IOException
	{
		ByteArrayOutputStream byteArrayOutputStream = new ByteArrayOutputStream();
		synchronized (ImageIO.class)
		{
			ImageIO.write(bufferedImage, "png", byteArrayOutputStream);
		}
		return byteArrayOutputStream.toByteArray();
	}

}

