package com.fogofwar.render;
import java.awt.BasicStroke;
import java.awt.Color;
import java.awt.Graphics2D;
import java.awt.Rectangle;
import java.awt.Shape;
import java.awt.Stroke;
import java.awt.geom.Area;
import java.awt.geom.GeneralPath;
public final class FogRender {
	private static final int SAILING_SEA_ALPHA_FLOOR = 16;
	private static final int SAILING_SEA_CACHE_SIZE = 16;
	private static final int[] SAILING_SEA_KEYS = new int[SAILING_SEA_CACHE_SIZE];
	private static final Color[] SAILING_SEA_VALUES = new Color[SAILING_SEA_CACHE_SIZE];
	private static int sailingSeaNext;
	private FogRender() {}
	public static void fill(GeneralPath path, Rectangle bounds, int padding, GeneralPath inner) {
		path.reset();
		path.moveTo(bounds.x - padding, bounds.y - padding);
		path.lineTo(bounds.x + bounds.width + padding, bounds.y - padding);
		path.lineTo(bounds.x + bounds.width + padding, bounds.y + bounds.height + padding);
		path.lineTo(bounds.x - padding, bounds.y + bounds.height + padding);
		path.closePath();
		path.append(inner, false);
	}
	public static void drawBorder(Graphics2D graphics, Shape path, Color color, StrokeCache borderStroke, int thickness) {
		Stroke oldStroke = graphics.getStroke();
		graphics.setColor(color);
		graphics.setStroke(borderStroke.get(thickness));
		graphics.draw(path);
		graphics.setStroke(oldStroke);
	}
	public static Area createDifferenceArea(Shape boundary, Shape innerBoundary) {
		Area area = new Area(boundary);
		area.subtract(new Area(innerBoundary));
		return area;
	}
	public static Color sailingSea(Color colour) {
		int rgb = colour.getRGB();
		for (int i = 0; i < SAILING_SEA_VALUES.length; i++) {
			Color cached = SAILING_SEA_VALUES[i];
			if (cached != null && SAILING_SEA_KEYS[i] == rgb) return cached;
		}
		Color sailingSea = new Color(colour.getRed(), colour.getGreen(), colour.getBlue(), Math.max(SAILING_SEA_ALPHA_FLOOR, colour.getAlpha() / 4));
		SAILING_SEA_KEYS[sailingSeaNext] = rgb;
		SAILING_SEA_VALUES[sailingSeaNext] = sailingSea;
		sailingSeaNext = (sailingSeaNext + 1) % SAILING_SEA_CACHE_SIZE;
		return sailingSea;
	}
	public static final class StrokeCache {
		private BasicStroke stroke;
		private int width = -1;
		public BasicStroke get(int w) {
			if (stroke == null || width != w) {
				stroke = new BasicStroke(w);
				width = w;
			}
			return stroke;
		}
	}
}

package com.fogofwar.render.world;
import com.fogofwar.coord.WorldEntityCoords;
import net.runelite.api.Actor;
import net.runelite.api.Client;
import net.runelite.api.Perspective;
import net.runelite.api.Player;
import net.runelite.api.Point;
import net.runelite.api.WorldView;
import net.runelite.api.coords.LocalPoint;
import net.runelite.api.coords.WorldPoint;
import java.awt.Rectangle;
import java.awt.Shape;
import java.awt.geom.Area;
import java.awt.geom.GeneralPath;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Comparator;
import java.util.List;
final class ActorCutoutMask {
	private static final int ACTOR_CUTOUT_BUCKET_SIZE = 48;
	private static final int PRIORITY_SCORE = Integer.MIN_VALUE / 2;
	private static final Comparator<ActorCutoutCandidate> ACTOR_CUTOUT_CANDIDATE_ORDER = (a, b) -> {
		int c = Integer.compare(a.score, b.score);
		if (c != 0) return c;
		c = Boolean.compare(!a.hit, !b.hit);
		if (c != 0) return c;
		c = Integer.compare(b.canvasY, a.canvasY);
		if (c != 0) return c;
		c = Integer.compare(a.canvasX, b.canvasX);
		if (c != 0) return c;
		c = Integer.compare(a.worldPoint.getX(), b.worldPoint.getX());
		if (c != 0) return c;
		return Integer.compare(a.worldPoint.getY(), b.worldPoint.getY());
	};
	private final Client client;
	private final VisibleActorTracker visibleActorTracker;
	private final ActorHullCache hullCache = new ActorHullCache();
	private final List<ActorCutoutCandidate> exclusionCandidates = new ArrayList<>(256);
	private boolean[] usedBuckets = new boolean[0];
	private Rectangle viewport;
	private Player localPlayer;
	private int exclusionCandidateCount;
	private int lastCamX, lastCamY, lastCamZ, lastCamPitch, lastCamYaw, lastScale, lastVpX, lastVpY, lastVpW, lastVpH;
	private boolean retainHullCache;
	ActorCutoutMask(Client client, VisibleActorTracker visibleActorTracker) {
		this.client = client;
		this.visibleActorTracker = visibleActorTracker;
	}
	void clearCaches() { hullCache.clear(); }
	void beginFrame() {
		updateCameraState();
		hullCache.beginFrame();
		retainHullCache = false;
	}
	void endFrame() {
		if (retainHullCache) hullCache.retainSeen();
	}
	void subtractExclusions(Area fogArea, Rectangle viewport, WorldView worldView, GeneralPath boundary, LocalPoint centerLp, int plane, int radius, int limit) {
		this.viewport = viewport;
		this.localPlayer = client.getLocalPlayer();
		retainHullCache = true;
		boolean all = limit == Integer.MAX_VALUE;
		int bucketColumns = all ? 1 : Math.max(1, (viewport.width + ACTOR_CUTOUT_BUCKET_SIZE - 1) / ACTOR_CUTOUT_BUCKET_SIZE);
		try {
			collectExclusionCandidates(worldView, boundary, centerLp, plane, radius, !all, bucketColumns);
			if (exclusionCandidateCount == 0) return;
			if (all) subtractAllExclusionAreas(fogArea, boundary);
			else {
				exclusionCandidates.subList(0, exclusionCandidateCount).sort(ACTOR_CUTOUT_CANDIDATE_ORDER);
				subtractSelectedExclusionAreas(fogArea, boundary, limit, bucketColumns);
			}
		} finally {
			clearExclusionCandidates();
			this.localPlayer = null;
		}
	}
	private void updateCameraState() {
		lastCamX = client.getCameraX();
		lastCamY = client.getCameraY();
		lastCamZ = client.getCameraZ();
		lastCamPitch = client.getCameraPitch();
		lastCamYaw = client.getCameraYaw();
		lastScale = client.getScale();
		lastVpX = client.getViewportXOffset();
		lastVpY = client.getViewportYOffset();
		lastVpW = client.getViewportWidth();
		lastVpH = client.getViewportHeight();
	}
	private void subtractAllExclusionAreas(Area fogArea, GeneralPath boundary) {
		for (int i = 0; i < exclusionCandidateCount; i++) {
			Area entryArea = getCandidateArea(exclusionCandidates.get(i), boundary);
			if (entryArea == null) continue;
			fogArea.subtract(entryArea);
		}
	}
	private void collectExclusionCandidates(WorldView worldView, GeneralPath boundary, LocalPoint centerLp, int plane, int radius, boolean ranked, int bucketColumns) {
		exclusionCandidateCount = 0;
		int localRadius = radius * Perspective.LOCAL_TILE_SIZE + Perspective.LOCAL_HALF_TILE_SIZE;
		if (localPlayer != null) collectExclusionCandidate(localPlayer, worldView, boundary, centerLp, plane, localRadius, ranked, bucketColumns);
		for (Actor actor : visibleActorTracker.getVisibleActors()) {
			if (actor == localPlayer) continue;
			collectExclusionCandidate(actor, worldView, boundary, centerLp, plane, localRadius, ranked, bucketColumns);
		}
	}
	private void collectExclusionCandidate(Actor actor, WorldView worldView, GeneralPath boundary, LocalPoint centerLp, int plane, int localRadius, boolean ranked, int bucketColumns) {
		if (actor == null) return;
		boolean priority = actor == localPlayer;
		WorldEntityCoords.ResolvedPoint location = WorldEntityCoords.resolveTopLevel(actor, worldView);
		if (location == null || location.worldPoint.getPlane() != plane) return;
		WorldView actorWv = actor.getWorldView();
		boolean onSubWorld = actorWv != null && !actorWv.isTopLevel();
		ActorHullCache.Entry cached = hullCache.get(actor);
		hullCache.markSeen(actor);
		int anim = actor.getAnimation(), frame = actor.getAnimationFrame();
		int pose = actor.getPoseAnimation(), poseFrame = actor.getPoseAnimationFrame();
		boolean hit = cached != null
				&& cached.wx == location.worldPoint.getX() && cached.wy == location.worldPoint.getY() && cached.plane == location.worldPoint.getPlane()
				&& cached.anim == anim && cached.frame == frame
				&& cached.pose == pose && cached.poseFrame == poseFrame
				&& cached.camX == lastCamX && cached.camY == lastCamY && cached.camZ == lastCamZ
				&& cached.camPitch == lastCamPitch && cached.camYaw == lastCamYaw
				&& cached.scale == lastScale
				&& cached.vpX == lastVpX && cached.vpY == lastVpY && cached.vpW == lastVpW && cached.vpH == lastVpH;
		if (hit) {
			if (!viewport.intersects(cached.bounds)) return;
			if (!priority && boundary.contains(cached.bounds)) return;
		}
		int localX, localY, canvasX, canvasY, edgeDistance;
		if (hit) {
			localX = cached.localX;
			localY = cached.localY;
			canvasX = cached.canvasX;
			canvasY = cached.canvasY;
			edgeDistance = getEdgeDistance(localX, localY, centerLp, localRadius);
		} else {
			LocalPoint lp = location.localPoint;
			localX = lp.getX();
			localY = lp.getY();
			edgeDistance = getEdgeDistance(localX, localY, centerLp, localRadius);
			int footprintRadius = Math.max(Perspective.LOCAL_TILE_SIZE, actor.getFootprintSize() * Perspective.LOCAL_TILE_SIZE / 2);
			if (!priority && !onSubWorld && edgeDistance < -footprintRadius) return;
			Point canvasPoint = Perspective.localToCanvas(client, lp, plane);
			if (!priority && (canvasPoint == null || !viewport.contains(canvasPoint.getX(), canvasPoint.getY()))) return;
			canvasX = canvasPoint != null ? canvasPoint.getX() : viewport.x + viewport.width / 2;
			canvasY = canvasPoint != null ? canvasPoint.getY() : viewport.y + viewport.height / 2;
		}
		int bucket = -1, score = 0;
		if (ranked) {
			if (viewport.contains(canvasX, canvasY)) bucket = getExclusionBucket(canvasX, canvasY, bucketColumns);
			score = getCandidateScore(actor, hit, edgeDistance);
		}
		addExclusionCandidate(actor, cached, location.worldPoint, anim, frame, pose, poseFrame, hit, score, bucket, canvasX, canvasY, localX, localY);
	}
	private int getEdgeDistance(int localX, int localY, LocalPoint centerLp, int localRadius) {
		int dx = Math.abs(localX - centerLp.getX());
		int dy = Math.abs(localY - centerLp.getY());
		return Math.max(dx, dy) - localRadius;
	}
	private int getCandidateScore(Actor actor, boolean hit, int edgeDistance) {
		if (actor == localPlayer) return PRIORITY_SCORE;
		int score = Math.abs(edgeDistance);
		if (edgeDistance < 0) score += Perspective.LOCAL_TILE_SIZE;
		if (!(actor instanceof Player)) score += Perspective.LOCAL_TILE_SIZE / 2;
		if (hit) score -= Perspective.LOCAL_TILE_SIZE * 8;
		return score;
	}
	private int getExclusionBucket(int canvasX, int canvasY, int bucketColumns) {
		int x = (canvasX - viewport.x) / ACTOR_CUTOUT_BUCKET_SIZE;
		int y = (canvasY - viewport.y) / ACTOR_CUTOUT_BUCKET_SIZE;
		return y * bucketColumns + x;
	}
	private void addExclusionCandidate(Actor actor, ActorHullCache.Entry cached, WorldPoint awp, int anim, int frame, int pose, int poseFrame, boolean hit, int score, int bucket, int canvasX, int canvasY, int localX, int localY) {
		if (exclusionCandidateCount == exclusionCandidates.size()) exclusionCandidates.add(new ActorCutoutCandidate());
		exclusionCandidates.get(exclusionCandidateCount++).set(actor, cached, awp, anim, frame, pose, poseFrame, hit, score, bucket, canvasX, canvasY, localX, localY);
	}
	private void subtractSelectedExclusionAreas(Area fogArea, GeneralPath boundary, int limit, int bucketColumns) {
		int bucketRows = Math.max(1, (viewport.height + ACTOR_CUTOUT_BUCKET_SIZE - 1) / ACTOR_CUTOUT_BUCKET_SIZE);
		int bucketCount = bucketColumns * bucketRows;
		if (usedBuckets.length < bucketCount) usedBuckets = new boolean[bucketCount];
		else Arrays.fill(usedBuckets, 0, bucketCount, false);
		int selected = subtractPriorityExclusionAreas(fogArea, boundary, limit);
		for (int pass = 0; pass < 2 && selected < limit; pass++) {
			for (int i = 0; i < exclusionCandidateCount && selected < limit; i++) {
				ActorCutoutCandidate candidate = exclusionCandidates.get(i);
				if (candidate.selected) continue;
				if (pass == 0 && candidate.bucket < 0) continue;
				if (pass == 0 && usedBuckets[candidate.bucket]) continue;
				Area entryArea = getCandidateArea(candidate, boundary);
				if (entryArea == null) continue;
				candidate.selected = true;
				if (candidate.bucket >= 0) usedBuckets[candidate.bucket] = true;
				fogArea.subtract(entryArea);
				selected++;
			}
		}
	}
	private int subtractPriorityExclusionAreas(Area fogArea, GeneralPath boundary, int limit) {
		int selected = 0;
		for (int i = 0; i < exclusionCandidateCount && selected < limit; i++) {
			ActorCutoutCandidate candidate = exclusionCandidates.get(i);
			if (candidate.actor != localPlayer) continue;
			Area entryArea = getCandidateArea(candidate, boundary);
			if (entryArea == null) continue;
			candidate.selected = true;
			fogArea.subtract(entryArea);
			selected++;
		}
		return selected;
	}
	private void clearExclusionCandidates() {
		for (int i = 0; i < exclusionCandidateCount; i++) exclusionCandidates.get(i).clear();
		exclusionCandidateCount = 0;
	}
	private Area getCandidateArea(ActorCutoutCandidate candidate, GeneralPath boundary) {
		ActorHullCache.Entry cached = candidate.cached;
		if (candidate.hit) {
			if (cached.area == null) cached.area = new Area(cached.hull);
			return cached.area;
		}
		Shape hull = candidate.actor.getConvexHull();
		if (hull == null) {
			if (cached != null) hullCache.remove(candidate.actor);
			return null;
		}
		Rectangle bounds = hull.getBounds();
		cached = hullCache.getOrCreate(candidate.actor);
		cached.hull = hull;
		cached.bounds = bounds;
		cached.area = null;
		cached.wx = candidate.worldPoint.getX();
		cached.wy = candidate.worldPoint.getY();
		cached.plane = candidate.worldPoint.getPlane();
		cached.localX = candidate.localX;
		cached.localY = candidate.localY;
		cached.canvasX = candidate.canvasX;
		cached.canvasY = candidate.canvasY;
		cached.anim = candidate.anim;
		cached.frame = candidate.frame;
		cached.pose = candidate.pose;
		cached.poseFrame = candidate.poseFrame;
		cached.camX = lastCamX;
		cached.camY = lastCamY;
		cached.camZ = lastCamZ;
		cached.camPitch = lastCamPitch;
		cached.camYaw = lastCamYaw;
		cached.scale = lastScale;
		cached.vpX = lastVpX;
		cached.vpY = lastVpY;
		cached.vpW = lastVpW;
		cached.vpH = lastVpH;
		if (!viewport.intersects(bounds)) return null;
		if (candidate.actor != localPlayer && boundary.contains(bounds)) return null;
		cached.area = new Area(hull);
		return cached.area;
	}
	private static final class ActorCutoutCandidate {
		private Actor actor;
		private ActorHullCache.Entry cached;
		private WorldPoint worldPoint;
		private int anim, frame, pose, poseFrame, score, bucket, canvasX, canvasY, localX, localY;
		private boolean hit, selected;
		private void set(Actor actor, ActorHullCache.Entry cached, WorldPoint worldPoint, int anim, int frame, int pose, int poseFrame, boolean hit, int score, int bucket, int canvasX, int canvasY, int localX, int localY) {
			this.actor = actor;
			this.cached = cached;
			this.worldPoint = worldPoint;
			this.anim = anim;
			this.frame = frame;
			this.pose = pose;
			this.poseFrame = poseFrame;
			this.hit = hit;
			this.score = score;
			this.bucket = bucket;
			this.canvasX = canvasX;
			this.canvasY = canvasY;
			this.localX = localX;
			this.localY = localY;
			this.selected = false;
		}
		private void clear() {
			actor = null;
			cached = null;
			worldPoint = null;
			anim = frame = pose = poseFrame = score = bucket = canvasX = canvasY = localX = localY = 0;
			hit = selected = false;
		}
	}
}

package com.fogofwar.render.world;
import com.fogofwar.lifecycle.LifecycleComponent;
import lombok.Getter;
import net.runelite.api.Actor;
import net.runelite.api.Renderable;
import net.runelite.api.events.BeforeRender;
import net.runelite.client.callback.RenderCallback;
import net.runelite.client.callback.RenderCallbackManager;
import net.runelite.client.eventbus.EventBus;
import net.runelite.client.eventbus.Subscribe;
import javax.inject.Inject;
import javax.inject.Singleton;
import java.util.Collections;
import java.util.IdentityHashMap;
import java.util.Set;
@Singleton
public class VisibleActorTracker extends LifecycleComponent implements RenderCallback {
	private final RenderCallbackManager renderCallbackManager;
	@Getter
	private final Set<Actor> visibleActors = Collections.newSetFromMap(new IdentityHashMap<>(256));
	@Inject
	public VisibleActorTracker(EventBus eventBus, RenderCallbackManager renderCallbackManager) {
		super(eventBus);
		this.renderCallbackManager = renderCallbackManager;
	}
	@Override
	protected void onStart() { renderCallbackManager.register(this); }
	@Override
	protected void onStop() {
		renderCallbackManager.unregister(this);
		visibleActors.clear();
	}
	@Subscribe
	@SuppressWarnings("unused")
	public void onBeforeRender(BeforeRender event) { visibleActors.clear(); }
	@Override
	public boolean addEntity(Renderable renderable, boolean ui) {
		if (!ui && renderable instanceof Actor) visibleActors.add((Actor) renderable);
		return true;
	}
}

package com.fogofwar.render.world;
import com.fogofwar.config.FogDisplayMode;
import com.fogofwar.config.FogOfWarConfig;
import com.fogofwar.render.RenderCenter;
import com.fogofwar.render.RenderCenterProvider;
import com.fogofwar.state.ClientState;
import net.runelite.api.Client;
import net.runelite.api.WorldView;
import net.runelite.api.coords.LocalPoint;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayLayer;
import net.runelite.client.ui.overlay.OverlayPosition;
import javax.inject.Inject;
import java.awt.Dimension;
import java.awt.Graphics2D;
import java.awt.Rectangle;
import java.awt.geom.GeneralPath;
public class WorldFogOverlay extends Overlay {
	private final Client client;
	private final FogOfWarConfig config;
	private final ClientState clientState;
	private final RenderCenterProvider renderCenterProvider;
	private final Rectangle viewport = new Rectangle();
	private final WorldRenderBoundary renderBoundary;
	private final WorldFogMask fogMask;
	private final ActorCutoutMask actorCutouts;
	@Inject
	public WorldFogOverlay(Client client, FogOfWarConfig config, ClientState clientState, RenderCenterProvider renderCenterProvider, VisibleActorTracker visibleActorTracker) {
		this.client = client;
		this.config = config;
		this.clientState = clientState;
		this.renderCenterProvider = renderCenterProvider;
		this.renderBoundary = new WorldRenderBoundary(client);
		this.fogMask = new WorldFogMask(config);
		this.actorCutouts = new ActorCutoutMask(client, visibleActorTracker);
		setPosition(OverlayPosition.DYNAMIC);
		setPriority(Overlay.PRIORITY_LOW);
		setLayer(OverlayLayer.ABOVE_SCENE);
	}
	public void clearCaches() { actorCutouts.clearCaches(); }
	@Override
	public Dimension render(Graphics2D graphics) {
		if (clientState.isClientNotReady()) return null;
		FogDisplayMode mode = config.worldDisplayMode();
		boolean showFog = mode.showsFog();
		boolean showBorder = mode.showsBorder();
		if (!showFog && !showBorder) return null;
		RenderCenter rc = renderCenterProvider.get();
		if (rc == null) return null;
		boolean useCutouts = showFog && config.actorCutoutLimit().isEnabled();
		if (useCutouts) actorCutouts.beginFrame();
		try {
			renderFrame(graphics, showFog, showBorder, rc);
		} finally {
			if (useCutouts) actorCutouts.endFrame();
		}
		return null;
	}
	private void renderFrame(Graphics2D graphics, boolean showFog, boolean showBorder, RenderCenter rc) {
		WorldView worldView = rc.getWorldView();
		int landRadius = config.landRenderDistance();
		boolean sailing = rc.isOnWorldEntity();
		int plane = rc.getWorldPoint().getPlane();
		setViewportBounds();
		if (sailing) renderSailingFrame(graphics, showFog, showBorder, rc, worldView, plane, landRadius);
		else renderLandFrame(graphics, showFog, showBorder, rc, worldView, plane, landRadius);
	}
	private void renderLandFrame(Graphics2D graphics, boolean showFog, boolean showBorder, RenderCenter rc, WorldView worldView, int plane, int landRadius) {
		LocalPoint landCenter = rc.snappedCenter();
		GeneralPath landBoundary = renderBoundary.createLandRenderAreaBoundary(rc, landRadius, viewport);
		if (landBoundary == null) {
			if (showFog) fogMask.renderFullFog(graphics, viewport);
			return;
		}
		if (showFog) fogMask.renderFog(graphics, viewport, worldView, landBoundary, landCenter, plane, landRadius, actorCutouts);
		if (showBorder) fogMask.renderBorder(graphics, landBoundary);
	}
	private void renderSailingFrame(Graphics2D graphics, boolean showFog, boolean showBorder, RenderCenter rc, WorldView worldView, int plane, int landRadius) {
		int seaRadius = config.sailingRenderDistance();
		LocalPoint center = rc.snappedCenter();
		GeneralPath seaBoundary = renderBoundary.createSeaRenderAreaBoundary(rc, seaRadius, viewport);
		if (seaBoundary == null) {
			if (showFog) fogMask.renderFullFog(graphics, viewport);
			return;
		}
		GeneralPath landBoundary = config.showLandAreaWhileSailing() ? renderBoundary.createLandRenderAreaBoundary(rc, landRadius, viewport) : null;
		if (showFog) {
			fogMask.renderFog(graphics, viewport, worldView, seaBoundary, center, plane, seaRadius, actorCutouts);
			if (landBoundary != null) fogMask.renderSailingSeaFog(graphics, viewport, worldView, seaBoundary, landBoundary, center, plane, landRadius, actorCutouts);
		}
		if (showBorder) {
			fogMask.renderBorder(graphics, seaBoundary);
			if (landBoundary != null) fogMask.renderSailingSeaBorder(graphics, landBoundary);
		}
	}
	private void setViewportBounds() {
		viewport.setBounds(client.getViewportXOffset(), client.getViewportYOffset(), client.getViewportWidth(), client.getViewportHeight());
	}
}

package com.fogofwar.render.world;
import com.fogofwar.render.BoundaryPathBuilder;
import com.fogofwar.render.RenderCenter;
import net.runelite.api.Client;
import net.runelite.api.Perspective;
import net.runelite.api.Point;
import net.runelite.api.WorldView;
import net.runelite.api.coords.LocalPoint;
import java.awt.Rectangle;
import java.awt.geom.GeneralPath;
import java.util.ArrayList;
import java.util.List;
final class WorldRenderBoundary implements BoundaryPathBuilder.Strategy {
	private final Client client;
	private final List<Point> boundaryPoints = new ArrayList<>(256);
	private final GeneralPath seaRenderAreaBoundary = new GeneralPath();
	private final GeneralPath landRenderAreaBoundary = new GeneralPath();
	private Rectangle currentViewport;
	private Point currentCenterPoint;
	WorldRenderBoundary(Client client) { this.client = client; }
	GeneralPath createSeaRenderAreaBoundary(RenderCenter rc, int radius, Rectangle viewport) {
		return buildRenderAreaBoundary(rc, radius, viewport, seaRenderAreaBoundary);
	}
	GeneralPath createLandRenderAreaBoundary(RenderCenter rc, int radius, Rectangle viewport) {
		return buildRenderAreaBoundary(rc, radius, viewport, landRenderAreaBoundary);
	}
	private GeneralPath buildRenderAreaBoundary(RenderCenter rc, int radius, Rectangle viewport, GeneralPath path) {
		WorldView worldView = rc.getWorldView();
		LocalPoint centerLp = rc.snappedCenter();
		int plane = rc.getWorldPoint().getPlane();
		if (centerLp == null) return null;
		boundaryPoints.clear();
		int localRadius = radius * Perspective.LOCAL_TILE_SIZE + Perspective.LOCAL_HALF_TILE_SIZE;
		int sampleCount = radius * 2 + 1;
		int step = localRadius * 2 / sampleCount;
		int minX = centerLp.getX() - localRadius;
		int maxX = centerLp.getX() + localRadius;
		int minY = centerLp.getY() - localRadius;
		int maxY = centerLp.getY() + localRadius;
		for (int i = 0; i < sampleCount; i++) addPoint(worldView, minX + i * step, maxY, plane);
		for (int i = 0; i < sampleCount; i++) addPoint(worldView, maxX, maxY - i * step, plane);
		for (int i = 0; i < sampleCount; i++) addPoint(worldView, maxX - i * step, minY, plane);
		for (int i = 0; i < sampleCount; i++) addPoint(worldView, minX, minY + i * step, plane);
		Point centerPoint = rc.getCanvasCenterPoint();
		if (centerPoint == null) centerPoint = new Point(viewport.x + viewport.width / 2, viewport.y + viewport.height - 1);
		currentViewport = viewport;
		currentCenterPoint = centerPoint;
		double arcRadius = Math.max(viewport.width, viewport.height) * 2.0;
		return BoundaryPathBuilder.build(path, boundaryPoints, centerPoint.getX(), centerPoint.getY(), arcRadius, this);
	}
	private void addPoint(WorldView worldView, int localX, int localY, int plane) {
		LocalPoint lp = new LocalPoint(localX, localY, worldView);
		boundaryPoints.add(Perspective.localToCanvas(client, lp, plane));
	}
	@Override
	public GeneralPath coverage(GeneralPath path) { return fallback(path); }
	@Override
	public boolean isValid(GeneralPath path) { return path != null && path.contains(currentCenterPoint.getX(), currentCenterPoint.getY()); }
	@Override
	public GeneralPath fallback(GeneralPath path) { return fullViewportCoveragePath(path); }
	private GeneralPath fullViewportCoveragePath(GeneralPath path) {
		Rectangle viewport = currentViewport;
		path.reset();
		path.moveTo(viewport.x - 1, viewport.y - 1);
		path.lineTo(viewport.x + viewport.width + 1, viewport.y - 1);
		path.lineTo(viewport.x + viewport.width + 1, viewport.y + viewport.height + 1);
		path.lineTo(viewport.x - 1, viewport.y + viewport.height + 1);
		path.closePath();
		return path;
	}
}

package com.fogofwar.render.world;
import com.fogofwar.config.ActorCutoutLimit;
import com.fogofwar.config.FogOfWarConfig;
import com.fogofwar.render.FogRender;
import com.fogofwar.render.FogRender.StrokeCache;
import net.runelite.api.WorldView;
import net.runelite.api.coords.LocalPoint;
import java.awt.Graphics2D;
import java.awt.Rectangle;
import java.awt.geom.Area;
import java.awt.geom.GeneralPath;
final class WorldFogMask {
	private final FogOfWarConfig config;
	private final GeneralPath fogPath = new GeneralPath(GeneralPath.WIND_EVEN_ODD);
	private final StrokeCache borderStroke = new StrokeCache();
	WorldFogMask(FogOfWarConfig config) { this.config = config; }
	void renderFog(Graphics2D graphics, Rectangle viewport, WorldView worldView, GeneralPath boundary, LocalPoint centerLp, int plane, int radius, ActorCutoutMask actorCutouts) {
		if (boundary.contains(viewport)) return;
		FogRender.fill(fogPath, viewport, 0, boundary);
		graphics.setColor(config.worldFogColour());
		ActorCutoutLimit cutoutLimit = config.actorCutoutLimit();
		if (!cutoutLimit.isEnabled()) {
			graphics.fill(fogPath);
			return;
		}
		Area fogArea = new Area(fogPath);
		actorCutouts.subtractExclusions(fogArea, viewport, worldView, boundary, centerLp, plane, radius, cutoutLimit.getLimit());
		graphics.fill(fogArea);
	}
	void renderFullFog(Graphics2D graphics, Rectangle viewport) {
		graphics.setColor(config.worldFogColour());
		graphics.fill(viewport);
	}
	void renderBorder(Graphics2D graphics, GeneralPath boundary) {
		FogRender.drawBorder(graphics, boundary, config.worldBorderColour(), borderStroke, config.worldBorderThickness());
	}
	void renderSailingSeaFog(Graphics2D graphics, Rectangle viewport, WorldView worldView, GeneralPath boundary, GeneralPath innerBoundary, LocalPoint centerLp, int plane, int radius, ActorCutoutMask actorCutouts) {
		Area area = FogRender.createDifferenceArea(boundary, innerBoundary);
		if (area.isEmpty()) return;
		ActorCutoutLimit cutoutLimit = config.actorCutoutLimit();
		if (cutoutLimit.isEnabled()) actorCutouts.subtractExclusions(area, viewport, worldView, innerBoundary, centerLp, plane, radius, cutoutLimit.getLimit());
		if (area.isEmpty()) return;
		graphics.setColor(FogRender.sailingSea(config.worldFogColour()));
		graphics.fill(area);
	}
	void renderSailingSeaBorder(Graphics2D graphics, GeneralPath boundary) {
		FogRender.drawBorder(graphics, boundary, FogRender.sailingSea(config.worldBorderColour()), borderStroke, config.worldBorderThickness());
	}
}

