}

package com.fogofwar.render.minimap;
import com.fogofwar.render.BoundaryPathBuilder;
import com.fogofwar.render.RenderCenter;
import net.runelite.api.Client;
import net.runelite.api.Perspective;
import net.runelite.api.Point;
import net.runelite.api.WorldView;
import net.runelite.api.coords.LocalPoint;
import net.runelite.api.coords.WorldPoint;
import java.awt.Rectangle;
import java.awt.geom.GeneralPath;
import java.util.ArrayList;
import java.util.List;
final class MinimapRenderBoundary implements BoundaryPathBuilder.Strategy {
	private static final int MINIMAP_RENDER_AREA_PADDING = 1;
	private final Client client;
	private final List<Point> boundaryPoints = new ArrayList<>(128);
	private final PathCache seaRenderAreaPath = new PathCache();
	private final PathCache landRenderAreaPath = new PathCache();
	private Rectangle currentMinimapBounds;
	private Point currentCenterPoint;
	private PathCache currentCache;
	MinimapRenderBoundary(Client client) { this.client = client; }
	void clearCaches() {
		seaRenderAreaPath.clear();
		landRenderAreaPath.clear();
	}
	GeneralPath createSeaRenderAreaPath(RenderCenter rc, int radius, Rectangle minimapBounds) {
		return buildRenderAreaPath(rc, radius, minimapBounds, seaRenderAreaPath);
	}
	GeneralPath createLandRenderAreaPath(RenderCenter rc, int radius, Rectangle minimapBounds) {
		return buildRenderAreaPath(rc, radius, minimapBounds, landRenderAreaPath);
	}
	private GeneralPath buildRenderAreaPath(RenderCenter rc, int radius, Rectangle minimapBounds, PathCache cache) {
		LocalPoint centerLp = rc.snappedCenter();
		WorldPoint centerWp = rc.getSnappedWorldPoint();
		if (centerWp == null) return null;
		currentMinimapBounds = minimapBounds;
		currentCenterPoint = rc.getMinimapCenterPoint();
		currentCache = cache;
		collectBoundaryPoints(rc.getWorldView(), centerWp, centerLp, radius);
		double arcRadius = Math.max(minimapBounds.width, minimapBounds.height) / 2.0 + 1;
		GeneralPath path = BoundaryPathBuilder.build(cache.working(), boundaryPoints, minimapBounds.getCenterX(), minimapBounds.getCenterY(), arcRadius, this);
		return path == cache.working() && isValid(path) ? cache.saveValid() : path;
	}
	@Override
	public GeneralPath coverage(GeneralPath path) { return fullMinimapCoveragePath(path); }
	@Override
	public boolean isValid(GeneralPath path) { return currentCenterPoint == null || path.contains(currentCenterPoint.getX(), currentCenterPoint.getY()); }
	@Override
	public GeneralPath fallback(GeneralPath path) { return currentCache.hasLastValid() ? currentCache.lastValid() : path; }
	private Point padRenderAreaPoint(Point point) {
		double cx = currentCenterPoint != null ? currentCenterPoint.getX() : currentMinimapBounds.getCenterX();
		double cy = currentCenterPoint != null ? currentCenterPoint.getY() : currentMinimapBounds.getCenterY();
		double dx = point.getX() - cx;
		double dy = point.getY() - cy;
		double distance = Math.hypot(dx, dy);
		if (distance == 0) return point;
		return new Point((int) Math.round(point.getX() + dx * MINIMAP_RENDER_AREA_PADDING / distance), (int) Math.round(point.getY() + dy * MINIMAP_RENDER_AREA_PADDING / distance));
	}
	private void collectBoundaryPoints(WorldView worldView, WorldPoint center, LocalPoint centerLp, int radius) {
		boundaryPoints.clear();
		int sampleRate = Math.max(1, radius / 12);
		int halfTile = Perspective.LOCAL_HALF_TILE_SIZE;
		addMinimapPoint(worldView, center, centerLp, -radius, -radius, -halfTile, -halfTile);
		for (int x = -radius; x <= radius; x += sampleRate) addMinimapPoint(worldView, center, centerLp, x, -radius, 0, -halfTile);
		addMinimapPoint(worldView, center, centerLp, radius, -radius, halfTile, -halfTile);
		for (int y = -radius; y <= radius; y += sampleRate) addMinimapPoint(worldView, center, centerLp, radius, y, halfTile, 0);
		addMinimapPoint(worldView, center, centerLp, radius, radius, halfTile, halfTile);
		for (int x = radius; x >= -radius; x -= sampleRate) addMinimapPoint(worldView, center, centerLp, x, radius, 0, halfTile);
		addMinimapPoint(worldView, center, centerLp, -radius, radius, -halfTile, halfTile);
		for (int y = radius; y >= -radius; y -= sampleRate) addMinimapPoint(worldView, center, centerLp, -radius, y, -halfTile, 0);
	}
	private void addMinimapPoint(WorldView worldView, WorldPoint centerWp, LocalPoint centerLp, int tileXOffset, int tileYOffset, int xOffset, int yOffset) {
		if (!WorldPoint.isInScene(worldView, centerWp.getX() + tileXOffset, centerWp.getY() + tileYOffset)) {
			boundaryPoints.add(null);
			return;
		}
		int x = centerLp.getX() + tileXOffset * Perspective.LOCAL_TILE_SIZE + xOffset;
		int y = centerLp.getY() + tileYOffset * Perspective.LOCAL_TILE_SIZE + yOffset;
		Point projected = Perspective.localToMinimap(client, new LocalPoint(x, y, worldView), RenderCenter.MINIMAP_PROJECTION_DISTANCE);
		boundaryPoints.add(projected == null ? null : padRenderAreaPoint(projected));
	}
	private GeneralPath fullMinimapCoveragePath(GeneralPath path) {
		Rectangle minimapBounds = currentMinimapBounds;
		path.reset();
		double centerX = minimapBounds.getCenterX();
		double centerY = minimapBounds.getCenterY();
		double radius = Math.max(minimapBounds.width, minimapBounds.height);
		int numSegments = 32;
		for (int i = 0; i < numSegments; i++) {
			double angle = 2 * Math.PI * i / numSegments;
			double x = centerX + radius * Math.cos(angle);
			double y = centerY + radius * Math.sin(angle);
			if (i == 0) path.moveTo(x, y);
			else path.lineTo(x, y);
		}
		path.closePath();
		return path;
	}
	private static final class PathCache {
		private GeneralPath working = new GeneralPath();
		private GeneralPath lastValid = new GeneralPath();
		private GeneralPath working() { return working; }
		private GeneralPath lastValid() { return lastValid; }
		private boolean hasLastValid() { return lastValid.getCurrentPoint() != null; }
		private GeneralPath saveValid() {
			GeneralPath valid = working;
			working = lastValid;
			lastValid = valid;
			working.reset();
			return lastValid;
		}
		private void clear() {
			working.reset();
			lastValid.reset();
		}
	}
}

package com.fogofwar.render.minimap;
import net.runelite.api.Client;
import net.runelite.api.gameval.InterfaceID;
import net.runelite.api.gameval.VarbitID;
import net.runelite.api.widgets.Widget;
import java.awt.Rectangle;
import java.awt.Shape;
import java.awt.geom.Area;
import java.awt.geom.Ellipse2D;
import java.util.Arrays;
import javax.inject.Inject;
import javax.inject.Singleton;
@Singleton
public final class MinimapClipProvider {
	private static final int RESIZED_MINIMAP_CLIP_PADDING = 1;
	private static final int FIXED_MINIMAP_CLIP_PADDING = 3;
	private static final int[] ORB_WIDGETS = {InterfaceID.Orbs.HEALTH_BACKING, InterfaceID.Orbs.PRAYER_BACKING, InterfaceID.Orbs.RUNENERGY_BACKING, InterfaceID.Orbs.SPECENERGY_BACKING, InterfaceID.Orbs.ORB_WORLDMAP};
	private final Client client;
	private final Rectangle[] currentOrbBounds = new Rectangle[ORB_WIDGETS.length];
	private Rectangle cachedMinimapBounds;
	private Shape cachedClipShape;
	private long cachedOrbsHash;
	private boolean cachedResized;
	@Inject
	public MinimapClipProvider(Client client) { this.client = client; }
	public Widget getMinimapWidget() {
		if (client.isResized()) {
			if (client.getVarbitValue(VarbitID.RESIZABLE_STONE_ARRANGEMENT) == 1) return client.getWidget(InterfaceID.ToplevelPreEoc.MINIMAP);
			return client.getWidget(InterfaceID.ToplevelOsrsStretch.MINIMAP);
		}
		return client.getWidget(InterfaceID.Toplevel.MINIMAP);
	}
	void clearCaches() {
		cachedMinimapBounds = null;
		cachedClipShape = null;
		cachedOrbsHash = 0;
		Arrays.fill(currentOrbBounds, null);
	}
	public Shape getClipShape(Widget minimapWidget) {
		Rectangle bounds = minimapWidget.getBounds();
		boolean resized = client.isResized();
		long orbsHash = collectOrbBoundsAndHash();
		if (cachedClipShape != null && bounds.equals(cachedMinimapBounds) && orbsHash == cachedOrbsHash && resized == cachedResized) return cachedClipShape;
		Area clipArea = createEllipse(bounds, resized ? RESIZED_MINIMAP_CLIP_PADDING : FIXED_MINIMAP_CLIP_PADDING);
		for (Rectangle ob : currentOrbBounds) {
			if (ob == null) continue;
			clipArea.subtract(createEllipse(ob, 0));
		}
		cachedClipShape = clipArea;
		cachedMinimapBounds = new Rectangle(bounds);
		cachedOrbsHash = orbsHash;
		cachedResized = resized;
		return cachedClipShape;
	}
	private static Area createEllipse(Rectangle bounds, int padding) { return new Area(new Ellipse2D.Double(bounds.getX() - padding, bounds.getY() - padding, bounds.getWidth() + padding * 2, bounds.getHeight() + padding * 2)); }
	private long collectOrbBoundsAndHash() {
		long h = 1469598103934665603L;
		for (int i = 0; i < ORB_WIDGETS.length; i++) {
			Widget orb = client.getWidget(ORB_WIDGETS[i]);
			Rectangle b = (orb != null && !orb.isHidden()) ? orb.getBounds() : null;
			currentOrbBounds[i] = b;
			if (b == null) h ^= 0xDEADBEEFL;
			else h ^= ((b.x & 0xFFFFL) << 48) ^ ((b.y & 0xFFFFL) << 32) ^ ((b.width & 0xFFFFL) << 16) ^ (b.height & 0xFFFFL);
			h *= 1099511628211L;
		}
		return h;
	}
}

package com.fogofwar.render.minimap;
import com.fogofwar.config.FogDisplayMode;
import com.fogofwar.config.FogOfWarConfig;
import com.fogofwar.render.RenderCenter;
import com.fogofwar.render.RenderCenterProvider;
import com.fogofwar.state.ClientState;
import net.runelite.api.Client;
import net.runelite.api.widgets.Widget;
import net.runelite.client.ui.overlay.Overlay;
import net.runelite.client.ui.overlay.OverlayLayer;
import net.runelite.client.ui.overlay.OverlayPosition;
import javax.inject.Inject;
import java.awt.Dimension;
import java.awt.Graphics2D;
import java.awt.Shape;
import java.awt.geom.GeneralPath;
public class MinimapFogOverlay extends Overlay {
	private final FogOfWarConfig config;
	private final ClientState clientState;
	private final RenderCenterProvider renderCenterProvider;
	private final MinimapClipProvider clipProvider;
	private final MinimapRenderBoundary renderBoundary;
	private final MinimapFogMask fogMask;
	@Inject
	public MinimapFogOverlay(Client client, FogOfWarConfig config, ClientState clientState, RenderCenterProvider renderCenterProvider, MinimapClipProvider clipProvider) {
		this.config = config;
		this.clientState = clientState;
		this.renderCenterProvider = renderCenterProvider;
		this.clipProvider = clipProvider;
		this.renderBoundary = new MinimapRenderBoundary(client);
		this.fogMask = new MinimapFogMask(config);
		setPosition(OverlayPosition.DYNAMIC);
		setPriority(Overlay.PRIORITY_LOW);
		setLayer(OverlayLayer.ABOVE_WIDGETS);
	}
	public void clearCaches() {
		clipProvider.clearCaches();
		renderBoundary.clearCaches();
	}
	@Override
	public Dimension render(Graphics2D graphics) {
		if (clientState.isClientNotReady()) return null;
		FogDisplayMode mode = config.minimapDisplayMode();
		boolean showFog = mode.showsFog();
		boolean showBorder = mode.showsBorder();
		if (!showFog && !showBorder) return null;
		Widget minimap = clipProvider.getMinimapWidget();
		if (minimap == null || minimap.isHidden()) return null;
		RenderCenter rc = renderCenterProvider.get();
		if (rc == null) return null;
		Shape minimapClipShape = clipProvider.getClipShape(minimap);
		Shape oldClip = graphics.getClip();
		graphics.setClip(minimapClipShape);
		try {
			int landRadius = config.landRenderDistance();
			if (rc.isOnWorldEntity()) renderSailingFrame(graphics, showFog, showBorder, rc, minimap, minimapClipShape, landRadius);
			else renderLandFrame(graphics, showFog, showBorder, rc, minimap, minimapClipShape, landRadius);
			return null;
		} finally { graphics.setClip(oldClip); }
	}
	private void renderLandFrame(Graphics2D graphics, boolean showFog, boolean showBorder, RenderCenter rc, Widget minimap, Shape minimapClipShape, int landRadius) {
		GeneralPath landPath = renderBoundary.createLandRenderAreaPath(rc, landRadius, minimap.getBounds());
		if (landPath == null) {
			if (showFog) fogMask.renderFullFog(graphics, minimapClipShape);
			return;
		}
		if (showFog) fogMask.renderFog(graphics, minimapClipShape, landPath);
		if (showBorder) fogMask.renderBorder(graphics, minimapClipShape, landPath);
	}
	private void renderSailingFrame(Graphics2D graphics, boolean showFog, boolean showBorder, RenderCenter rc, Widget minimap, Shape minimapClipShape, int landRadius) {
		int seaRadius = config.sailingRenderDistance();
		GeneralPath seaPath = renderBoundary.createSeaRenderAreaPath(rc, seaRadius, minimap.getBounds());
		if (seaPath == null) {
			if (showFog) fogMask.renderFullFog(graphics, minimapClipShape);
			return;
		}
		GeneralPath landPath = config.showLandAreaWhileSailing() ? renderBoundary.createLandRenderAreaPath(rc, landRadius, minimap.getBounds()) : null;
		if (showFog) {
			fogMask.renderFog(graphics, minimapClipShape, seaPath);
			if (landPath != null) fogMask.renderSailingSeaFog(graphics, seaPath, landPath);
		}
		if (showBorder) {
			fogMask.renderBorder(graphics, minimapClipShape, seaPath);
			if (landPath != null) fogMask.renderSailingSeaBorder(graphics, minimapClipShape, landPath);
		}
	}
}

package com.fogofwar.render.minimap;
import com.fogofwar.config.FogOfWarConfig;
import com.fogofwar.render.FogRender;
import com.fogofwar.render.FogRender.StrokeCache;
import java.awt.Graphics2D;
import java.awt.Rectangle;
import java.awt.Shape;
import java.awt.geom.Area;
import java.awt.geom.GeneralPath;
final class MinimapFogMask {
	private final FogOfWarConfig config;
	private final GeneralPath fogFillPath = new GeneralPath(GeneralPath.WIND_EVEN_ODD);
	private final StrokeCache borderStroke = new StrokeCache();
	MinimapFogMask(FogOfWarConfig config) { this.config = config; }
	void renderFog(Graphics2D graphics, Shape minimapClipShape, GeneralPath path) {
		if (path.contains(minimapClipShape.getBounds2D())) return;
		Rectangle b = minimapClipShape.getBounds();
		FogRender.fill(fogFillPath, b, 1, path);
		graphics.setColor(config.minimapFogColour());
		graphics.fill(fogFillPath);
	}
	void renderFullFog(Graphics2D graphics, Shape minimapClipShape) {
		graphics.setColor(config.minimapFogColour());
		graphics.fill(minimapClipShape);
	}
	void renderBorder(Graphics2D graphics, Shape minimapClipShape, GeneralPath path) {
		if (path.contains(minimapClipShape.getBounds2D())) return;
		FogRender.drawBorder(graphics, path, config.minimapBorderColour(), borderStroke, config.minimapBorderThickness());
	}
	void renderSailingSeaFog(Graphics2D graphics, GeneralPath boundary, GeneralPath innerBoundary) {
		Area area = FogRender.createDifferenceArea(boundary, innerBoundary);
		if (area.isEmpty()) return;
		graphics.setColor(FogRender.sailingSea(config.minimapFogColour()));
		graphics.fill(area);
	}
	void renderSailingSeaBorder(Graphics2D graphics, Shape minimapClipShape, GeneralPath path) {
		if (path.contains(minimapClipShape.getBounds2D())) return;
		FogRender.drawBorder(graphics, path, FogRender.sailingSea(config.minimapBorderColour()), borderStroke, config.minimapBorderThickness());
	}
}

package com.fogofwar.render;
import com.fogofwar.coord.WorldEntityCoords;
import lombok.Getter;
import net.runelite.api.Client;
import net.runelite.api.Perspective;
import net.runelite.api.Player;
import net.runelite.api.Point;
import net.runelite.api.WorldEntity;
import net.runelite.api.WorldView;
import net.runelite.api.coords.LocalPoint;
import net.runelite.api.coords.WorldPoint;
public final class RenderCenter {
	public static final int MINIMAP_PROJECTION_DISTANCE = 32768;
	@Getter
	private final WorldView worldView;
	@Getter
	private final WorldPoint worldPoint;
	private final LocalPoint snappedCenter;
	@Getter
	private final WorldPoint snappedWorldPoint;
	@Getter
	private final Point canvasCenterPoint;
	@Getter
	private final Point minimapCenterPoint;
	@Getter
	private final boolean onWorldEntity;
	private RenderCenter(Client client, WorldView worldView, WorldPoint worldPoint, LocalPoint localPoint, LocalPoint targetLocalPoint, boolean onWorldEntity) {
		this.worldView = worldView;
		this.worldPoint = worldPoint;
		this.onWorldEntity = onWorldEntity;
		this.snappedCenter = snapCenter(onWorldEntity ? targetLocalPoint : localPoint, worldView);
		this.snappedWorldPoint = WorldPoint.fromLocal(worldView, snappedCenter.getX(), snappedCenter.getY(), worldPoint.getPlane());
		this.canvasCenterPoint = Perspective.localToCanvas(client, snappedCenter, worldPoint.getPlane());
		this.minimapCenterPoint = Perspective.localToMinimap(client, snappedCenter, MINIMAP_PROJECTION_DISTANCE);
	}
	public static RenderCenter resolve(Client client) {
		Player p = client.getLocalPlayer();
		if (p == null) return null;
		WorldView pwv = p.getWorldView();
		WorldView topWv = client.getTopLevelWorldView();
		if (topWv == null) return null;
		if (pwv == null || pwv.isTopLevel()) {
			WorldPoint wp = p.getWorldLocation();
			LocalPoint lp = wp != null ? LocalPoint.fromWorld(topWv, wp) : null;
			if (wp == null || lp == null) return null;
			return new RenderCenter(client, topWv, wp, lp, lp, false);
		}
		WorldEntity we = WorldEntityCoords.getPlayerWorldEntity(p, topWv);
		if (we == null) return null;
		if (!WorldEntityCoords.isShip(we)) {
			WorldEntityCoords.ResolvedPoint point = WorldEntityCoords.resolveTopLevel(p, pwv, topWv, we);
			return point != null ? new RenderCenter(client, topWv, point.worldPoint, point.localPoint, point.localPoint, false) : null;
		}
		LocalPoint boatLp = we.getLocalLocation();
		if (boatLp == null) return null;
		LocalPoint boatTarget = we.getTargetLocation();
		if (boatTarget == null) boatTarget = boatLp;
		WorldPoint boatWp = WorldEntityCoords.toTopLevelWorldPoint(topWv, boatLp);
		return new RenderCenter(client, topWv, boatWp, boatLp, boatTarget, true);
	}
	public LocalPoint snappedCenter() { return snappedCenter; }
	private static LocalPoint snapCenter(LocalPoint lp, WorldView worldView) {
		return new LocalPoint(snapAxis(lp.getX()), snapAxis(lp.getY()), worldView);
	}
	private static int snapAxis(int current) { return (current / Perspective.LOCAL_TILE_SIZE) * Perspective.LOCAL_TILE_SIZE + Perspective.LOCAL_HALF_TILE_SIZE; }
}

package com.fogofwar.render;
import net.runelite.api.Point;
import java.awt.geom.GeneralPath;
import java.util.List;
public final class BoundaryPathBuilder {
	public interface Strategy {
		GeneralPath coverage(GeneralPath path);
		boolean isValid(GeneralPath path);
		GeneralPath fallback(GeneralPath path);
	}
	private BoundaryPathBuilder() {}
	public static GeneralPath build(GeneralPath path, List<Point> points, double arcCenterX, double arcCenterY, double arcRadius, Strategy strategy) {
		GeneralPath result = buildPath(path, points, arcCenterX, arcCenterY, arcRadius, strategy, false);
		if (strategy.isValid(result)) return result;
		result = buildPath(path, points, arcCenterX, arcCenterY, arcRadius, strategy, true);
		if (strategy.isValid(result)) return result;
		return strategy.fallback(result);
	}
	private static GeneralPath buildPath(GeneralPath path, List<Point> points, double arcCenterX, double arcCenterY, double arcRadius, Strategy strategy, boolean reverseArc) {
		int n = points.size();
		int firstVisible = -1;
		int visibleCount = 0;
		for (int i = 0; i < n; i++) {
			if (points.get(i) != null) {
				if (firstVisible == -1) firstVisible = i;
				visibleCount++;
			}
		}
		if (visibleCount == 0) return strategy.coverage(path);
		path.reset();
		if (visibleCount == n) return buildCompletePath(path, points);
		Point first = points.get(firstVisible);
		path.moveTo(first.getX(), first.getY());
		for (int i = 0; i < n; i++) {
			int currentIndex = (firstVisible + i) % n;
			int nextIndex = (firstVisible + i + 1) % n;
			Point p1 = points.get(currentIndex);
			Point p2 = points.get(nextIndex);
			if (p1 == null) continue;
			if (p2 != null) path.lineTo(p2.getX(), p2.getY());
			else {
				int nextVisibleIndex = findNextVisibleIndex(points, currentIndex, n);
				if (nextVisibleIndex != -1) addArcToPath(path, p1, points.get(nextVisibleIndex), arcCenterX, arcCenterY, arcRadius, reverseArc);
			}
		}
		path.closePath();
		return path;
	}
	private static GeneralPath buildCompletePath(GeneralPath path, List<Point> points) {
		Point first = points.get(0);
		path.moveTo(first.getX(), first.getY());
		for (int i = 1; i < points.size(); i++) {
			Point point = points.get(i);
			path.lineTo(point.getX(), point.getY());
		}
		path.closePath();
		return path;
	}
	private static int findNextVisibleIndex(List<Point> points, int currentIndex, int n) {
		for (int i = 2; i < n; i++) {
			int index = (currentIndex + i) % n;
			if (points.get(index) != null) return index;
		}
		return -1;
	}
	private static void addArcToPath(GeneralPath path, Point p1, Point p2, double centerX, double centerY, double radius, boolean reverse) {
		double startAngle = Math.toDegrees(Math.atan2(p1.getY() - centerY, p1.getX() - centerX));
		double endAngle = Math.toDegrees(Math.atan2(p2.getY() - centerY, p2.getX() - centerX));
		double sweep = endAngle - startAngle;
		if (sweep <= -180) { sweep += 360; } else if (sweep > 180) { sweep -= 360; }
		if (reverse) sweep += sweep > 0 ? -360 : 360;
		int numSteps = (int) (Math.abs(sweep) / 10) + 1;
		for (int i = 1; i <= numSteps; i++) {
			double angle = Math.toRadians(startAngle + sweep * i / numSteps);
			path.lineTo((float) (centerX + radius * Math.cos(angle)), (float) (centerY + radius * Math.sin(angle)));
		}
	}
}

package com.fogofwar.fade;
import com.fogofwar.config.FogOfWarConfig;
import com.fogofwar.area.AreaExclusionManager;
import com.fogofwar.coord.WorldEntityCoords;
import com.fogofwar.lifecycle.LifecycleComponent;
import lombok.Getter;
import net.runelite.api.Client;
import net.runelite.api.GameState;
import net.runelite.api.Player;
import net.runelite.api.WorldEntity;
import net.runelite.api.WorldView;
import net.runelite.api.coords.WorldPoint;
import net.runelite.api.events.GameStateChanged;
import net.runelite.api.events.GameTick;
import net.runelite.client.eventbus.EventBus;
import net.runelite.client.eventbus.Subscribe;
import javax.inject.Inject;
import javax.inject.Singleton;
import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;
@Singleton
public class FadingPlayerManager extends LifecycleComponent {
	private final Client client;
	private final FogOfWarConfig config;
	private final AreaExclusionManager areaExclusionManager;
	@Getter
	private final Map<Player, FadingPlayer> fadingPlayers = new HashMap<>();
	private Map<Player, TrackedPlayer> lastTickPlayerLocations = new HashMap<>();
	private Map<Player, TrackedPlayer> twoTicksAgoPlayerLocations = new HashMap<>();
	private Map<Player, TrackedPlayer> currentPlayerLocations = new HashMap<>();
	private final Set<String> currentPlayerNames = new HashSet<>();
	private final FadingPlayerPredictor predictor = new FadingPlayerPredictor();
	@Inject
	public FadingPlayerManager(Client client, FogOfWarConfig config, EventBus eventBus, AreaExclusionManager areaExclusionManager) {
		super(eventBus);
		this.client = client;
		this.config = config;
		this.areaExclusionManager = areaExclusionManager;
	}
	@Override
	protected void onStop() { clearAllTracking(); }
	@Subscribe
	@SuppressWarnings("unused")
	public void onGameStateChanged(GameStateChanged event) {
		if (event.getGameState() == GameState.LOADING) clearAllTracking();
	}
	@Subscribe
	@SuppressWarnings("unused")
	public void onGameTick(GameTick event) {
		Player localPlayer = client.getLocalPlayer();
		WorldView worldView = client.getTopLevelWorldView();
		WorldPoint localPlayerLocation = localPlayer != null && worldView != null ? WorldEntityCoords.playerToTopLevel(localPlayer, null, worldView) : null;
		if (client.getGameState() != GameState.LOGGED_IN || localPlayer == null || worldView == null || localPlayerLocation == null) {
			clearAllTracking();
			return;
		}
		if (areaExclusionManager.isPlayerInExcludedArea()) {
			clearAllTracking();
			return;
		}
		boolean onWorldEntity = isOnWorldEntity(localPlayer);
		if (config.disableWhileSailing() && onWorldEntity) {
			clearAllTracking();
			return;
		}
		int fadeDuration = config.fadeDurationTicks();
		boolean extrapolate = config.predictMovement();
		boolean onlyAtLimit = config.onlyFadeAtRenderEdge();
		handleFadingPlayers(fadeDuration, extrapolate, localPlayerLocation);
		updatePlayerTracking(extrapolate, onlyAtLimit, localPlayer, worldView, localPlayerLocation, onWorldEntity);
	}
	private void clearAllTracking() {
		fadingPlayers.clear();
		lastTickPlayerLocations.clear();
		twoTicksAgoPlayerLocations.clear();
		currentPlayerLocations.clear();
		currentPlayerNames.clear();
	}
	private void handleFadingPlayers(int fadeDuration, boolean extrapolate, WorldPoint localPlayerLocation) {
		fadingPlayers.entrySet().removeIf(entry -> {
			FadingPlayer fp = entry.getValue();
			fp.setTicksSinceDisappeared(fp.getTicksSinceDisappeared() + 1);
			if (fp.getTicksSinceDisappeared() > fadeDuration) return true;
			WorldPoint markerLocation = fp.getMarkerLocation();
			if (fp.getTicksSinceDisappeared() > 1 && markerLocation.distanceTo(localPlayerLocation) <= fp.getRenderDistance()) return true;
			WorldPoint velocity = fp.getVelocity();
			if (extrapolate && velocity != null) {
				fp.setMarkerLocation(new WorldPoint(
						markerLocation.getX() + velocity.getX(),
						markerLocation.getY() + velocity.getY(),
						markerLocation.getPlane()));
			}
			return false;
		});
	}
	private void updatePlayerTracking(boolean extrapolate, boolean onlyAtLimit, Player localPlayer, WorldView worldView, WorldPoint localPlayerLocation, boolean onWorldEntity) {
		currentPlayerLocations.clear();
		currentPlayerNames.clear();
		trackPlayers(localPlayer, worldView, worldView, config.landRenderDistance());
		int boatRenderDistance = onWorldEntity ? config.sailingRenderDistance() : config.landRenderDistance();
		for (WorldEntity worldEntity : worldView.worldEntities()) {
			if (worldEntity == null) continue;
			WorldView entityWorldView = worldEntity.getWorldView();
			if (entityWorldView == null) continue;
			trackPlayers(localPlayer, entityWorldView, worldView, boatRenderDistance);
		}
		for (Map.Entry<Player, TrackedPlayer> entry : lastTickPlayerLocations.entrySet()) {
			Player player = entry.getKey();
			if (currentPlayerLocations.containsKey(player)) continue;
			if (fadingPlayers.containsKey(player)) continue;
			TrackedPlayer lastTickPlayer = entry.getValue();
			WorldPoint lastLocation = lastTickPlayer.getLocation();
			if (lastLocation == null) continue;
			int renderDistance = lastTickPlayer.getRenderDistance();
			boolean needsVelocity = onlyAtLimit || extrapolate;
			WorldPoint velocity = null;
			boolean nearRenderLimit = false;
			if (needsVelocity) {
				TrackedPlayer twoTicksAgoPlayer = twoTicksAgoPlayerLocations.get(player);
				WorldPoint twoTicksAgoLocation = twoTicksAgoPlayer != null ? twoTicksAgoPlayer.getLocation() : null;
				velocity = predictor.getVelocity(lastLocation, twoTicksAgoLocation);
				nearRenderLimit = predictor.isNearRenderLimit(lastLocation, localPlayerLocation, velocity, renderDistance);
			}
			if (onlyAtLimit && !nearRenderLimit) continue;
			WorldPoint initialFadeLocation = extrapolate ? predictor.getInitialFadeLocation(lastLocation, localPlayerLocation, velocity, true, renderDistance, nearRenderLimit) : lastLocation;
			fadingPlayers.put(player, new FadingPlayer(player, velocity, initialFadeLocation, renderDistance));
		}
		Map<Player, TrackedPlayer> tmp = twoTicksAgoPlayerLocations;
		twoTicksAgoPlayerLocations = lastTickPlayerLocations;
		lastTickPlayerLocations = currentPlayerLocations;
		currentPlayerLocations = tmp;
		fadingPlayers.entrySet().removeIf(entry -> {
			String name = entry.getKey().getName();
			return name != null && currentPlayerNames.contains(name);
		});
	}
	private void trackPlayers(Player localPlayer, WorldView worldView, WorldView topWorldView, int renderDistance) {
		for (Player player : worldView.players()) {
			if (player == null || player == localPlayer) continue;
			WorldPoint playerLocation = WorldEntityCoords.playerToTopLevel(player, worldView, topWorldView);
			if (playerLocation != null) currentPlayerLocations.put(player, new TrackedPlayer(playerLocation, renderDistance));
			if (player.getName() != null) currentPlayerNames.add(player.getName());
		}
	}
	private boolean isOnWorldEntity(Player player) {
		return WorldEntityCoords.isPlayerOnShip(player, client.getTopLevelWorldView());
	}
	@Getter
	private static class TrackedPlayer {
		private final WorldPoint location;
		private final int renderDistance;
		private TrackedPlayer(WorldPoint location, int renderDistance) {
			this.location = location;
			this.renderDistance = renderDistance;
		}
	}
}

