package com.fogofwar.config;
import org.junit.Test;
import static org.junit.Assert.assertEquals;
public class FogOfWarConfigMigrationTest {
	@Test
	public void toFogDisplayModeKeepsOldToggleSemantics() {
		assertEquals(FogDisplayMode.BOTH, FogOfWarConfigMigration.toFogDisplayMode(true, true));
		assertEquals(FogDisplayMode.FOG, FogOfWarConfigMigration.toFogDisplayMode(true, false));
		assertEquals(FogDisplayMode.BORDER, FogOfWarConfigMigration.toFogDisplayMode(false, true));
		assertEquals(FogDisplayMode.OFF, FogOfWarConfigMigration.toFogDisplayMode(false, false));
	}
	@Test
	public void toFadingPlayerModeKeepsOldToggleSemantics() {
		assertEquals(FadingPlayerMode.OFF, FogOfWarConfigMigration.toFadingPlayerMode(false, true, true));
		assertEquals(FadingPlayerMode.BOTH, FogOfWarConfigMigration.toFadingPlayerMode(true, true, true));
		assertEquals(FadingPlayerMode.WORLD, FogOfWarConfigMigration.toFadingPlayerMode(true, true, false));
		assertEquals(FadingPlayerMode.MINIMAP, FogOfWarConfigMigration.toFadingPlayerMode(true, false, true));
		assertEquals(FadingPlayerMode.OFF, FogOfWarConfigMigration.toFadingPlayerMode(true, false, false));
	}
	@Test
	public void toActorCutoutLimitKeepsOldToggleSemantics() {
		assertEquals(ActorCutoutLimit.LIMIT_64, FogOfWarConfigMigration.toActorCutoutLimit(true));
		assertEquals(ActorCutoutLimit.NONE, FogOfWarConfigMigration.toActorCutoutLimit(false));
	}
}

package com.fogofwar.fade;
import net.runelite.api.coords.WorldPoint;
import org.junit.Test;
import static org.junit.Assert.assertEquals;
import static org.junit.Assert.assertFalse;
import static org.junit.Assert.assertTrue;
public class FadingPlayerPredictorTest {
	private final FadingPlayerPredictor predictor = new FadingPlayerPredictor();
	@Test
	public void velocityUsesLastTwoLocations() {
		assertEquals(new WorldPoint(2, -1, 0), predictor.getVelocity(new WorldPoint(12, 19, 0), new WorldPoint(10, 20, 0)));
		assertEquals(new WorldPoint(0, 0, 0), predictor.getVelocity(new WorldPoint(12, 19, 0), null));
	}
	@Test
	public void nearRenderLimitHonorsEdgeAndRunning() {
		WorldPoint local = new WorldPoint(100, 100, 0);
		assertTrue(predictor.isNearRenderLimit(new WorldPoint(114, 100, 0), local, new WorldPoint(0, 0, 0), 15));
		assertFalse(predictor.isNearRenderLimit(new WorldPoint(112, 100, 0), local, new WorldPoint(1, 0, 0), 15));
		assertTrue(predictor.isNearRenderLimit(new WorldPoint(113, 100, 0), local, new WorldPoint(2, 0, 0), 15));
	}
	@Test
	public void initialLocationMatchesExtrapolationRules() {
		WorldPoint local = new WorldPoint(100, 100, 0);
		assertEquals(new WorldPoint(116, 100, 0), predictor.getInitialFadeLocation(new WorldPoint(114, 100, 0), local, new WorldPoint(1, 0, 0), true, 15, true));
		assertEquals(new WorldPoint(114, 100, 0), predictor.getInitialFadeLocation(new WorldPoint(114, 100, 0), local, new WorldPoint(-1, 0, 0), true, 15, true));
		assertEquals(new WorldPoint(114, 100, 0), predictor.getInitialFadeLocation(new WorldPoint(114, 100, 0), local, new WorldPoint(1, 0, 0), false, 15, true));
	}
}

