	private void renderOptimizerEmptyFromSummary(com.o7flip.model.OptimizeResult.Summary s)
	{
		String title = "No allocations possible";
		String sub;
		if (s != null && s.emptyReason != null && !s.emptyReason.isEmpty())
		{
