            case BLOAT:
                liveFrame.addBloatLine(value, description);
                break;
            case NYLOCAS:
                liveFrame.addNyloLine(value, description);
                break;
            case SOTETSEG:
                liveFrame.addSoteLine(value, description);
                break;
            case XARPUS:
                liveFrame.addXarpLine(value, description);
                break;
            case VERZIK:
                liveFrame.addVerzikLine(value, description);
                break;
        }
    }

