    public void reset()
    {
        currentWave = 0;
        roomState = NOT_STARTED;
        pillarsSpawnedTick = -1;
        instanceReference = -1;
        instanceStart = -1;
        bossSpawn = -1;
        lastDead = -1;
        accurateEntry = true;
        entryTickOffset = -1;
        hard = false;
        story = false;
        wave31 = -1;
        bigsDeadThisTick.clear();
        bigDescription.clear();
        super.reset();
