		gbc.gridy = 1;
		gbc.fill = GridBagConstraints.NONE;
		gbc.weightx = 0.0;
		mainPanel.add(secretKeyLabel, gbc);

		secretKeyField = new JTextField(20);
		secretKeyField.setBackground(ColorScheme.DARKER_GRAY_COLOR);
		secretKeyField.setForeground(Color.WHITE);
