		ConfigChanged event = new ConfigChanged();
		event.setGroup(HealthbarIndicatorsConfig.CONFIG_GROUP);
		event.setKey(HealthbarIndicatorsConfig.TRACKED_EFFECTS_KEY);
		plugin.onConfigChanged(event);
	}

